window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["o"]={"Oleksandr": "<p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Oskar": "<b>Oskar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> oznaczające „bożą włócznię” lub „włócznię boga” (<i>os</i> lub <i>ans</i> „bóg” i <i>gār</i> „włócznia”) lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">iryjskiego</a>, gdzie oznaczało „przyjaciela jeleni” (<i>os</i> „jeleń”, <i>cara</i> „przyjaciel”). W tekstach po polsku pojawiło się w XV wieku. Imię to nosili m.in. królowie <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">Szwecji</a>. Jego wariantem przyjętym w Polsce jest <b>Ansgar</b>.", "Oliwier": "<b>Oliwer</b>, <b>Oliwier</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Normanowie\" target=\"_blank\" rel=\"noopener noreferrer\">normandzkiego</a>. Wywodzi się od zniekształconego słowa <i>Alfihar</i> oznaczającego „armia elfów”. Z czasem wymowa imienia została zmieniona i zaczęto je wiązać z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a> <i>oliva</i> oznaczającym „drzewo oliwne”. W średniowieczu przybierało ono w Polsce formy <b>Oliwir</b>, <b>Olwir</b>, <b>Olwer</b>. Imię błędnie uznawane za męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Oliwia\" target=\"_blank\" rel=\"noopener noreferrer\">Oliwii</a>.", "Oleh": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleg</b>.</p><b>Oleg</b> – rosyjskie imię męskie pochodzenia skandynawskiego (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a>). Występuje ono także w innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach wschodniosłowiańskich</a>, a wywodzi się tam ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroruski\" target=\"_blank\" rel=\"noopener noreferrer\">staroruskiego</a> Ольгъ, zapożyczonego z kolei ze staronordyjskiego <em>Helgi</em> (por. staronorweskie <i>heill</i> „cieszący się pomyślnością, szczęśliwy”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heilig</em> „święty”).", "Oleksii": "<p>Oleksii, Oleksii lub Oleksiĭ (ukrainański: Олексій [olekˈs (j) ij]) to ukraińskie imię męskie pochodzące z starożytnego Grecji.</p>", "Olaf": "<b>Olaf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Pierwotna forma brzmiała Aslaf. Wywodzi się od słów <i>As</i> (bóg – zobacz <a href=\"https://pl.wikipedia.org/wiki/Azowie\" target=\"_blank\" rel=\"noopener noreferrer\">Asowie</a>) i <i>laf</i> (słowo, które przeszło w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> <i>love</i>), czyli „umiłowany przez bogów”. Inna wersja etymologii głosi, że imię ma znaczenie „syn starego człowieka”.", "Olivier": "<p>Guillaume-Antoine Olivier (francuski: Guillaume - Antoine Olivier, 19 stycznia 1756, Toulon - 1 października 1814, Lyon) - francuski naturalista, botanik, entomolog, zoolog, arachnolog i karcinolog.</p>", "Oliver": "<p>Walter Reginald Brook Oliver (w. 7 września 1883, Lonseston - 16 maja 1957, Wellington) - nowozelandski botanik i ornitolog.</p>", "Oleg": "<b>Oleg</b> – rosyjskie imię męskie pochodzenia skandynawskiego (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a>). Występuje ono także w innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach wschodniosłowiańskich</a>, a wywodzi się tam ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroruski\" target=\"_blank\" rel=\"noopener noreferrer\">staroruskiego</a> Ольгъ, zapożyczonego z kolei ze staronordyjskiego <em>Helgi</em> (por. staronorweskie <i>heill</i> „cieszący się pomyślnością, szczęśliwy”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heilig</em> „święty”).", "Olgierd": "<b>Olgierd</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Litwa\" target=\"_blank\" rel=\"noopener noreferrer\">litewskiego</a> (po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> <i>Algirdas</i>). Jego drugi człon łączony jest z lit. czasownikiem <i>girti</i> – „chwalić, sławić”; pierwszy człon, <i>Al-</i>, jest niejasny&#8201;, jednak niektórzy badacze dopatrują się w nim odpowiednika <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a> <i>al</i> – „cały, wszystek”, na podstawie podobieństwa do lit. <i>aliai</i> – „każdy”; Olgierd (<i>Algirdas</i>) oznaczałoby wówczas „wszystek sławny”, „przesławny”&#8201;. Jako imię chrzestne <b>Olgierd</b> pojawia się w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>, na początku w litewskich rodach arystokratycznych, przypuszczalnie nie bez związku z powieścią historyczną <a href=\"https://pl.wikipedia.org/wiki/Alexander_von_Oppeln-Bronikowski\" target=\"_blank\" rel=\"noopener noreferrer\">A. Bronikowskiego</a> „<i>Olgierd i <a href=\"https://pl.wikipedia.org/wiki/Olga\" target=\"_blank\" rel=\"noopener noreferrer\">Olga</a> czyli Polska w jedenastym wieku</i>” (1828)&#8201;.", "Oscar": "<p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oliwer": "<b>Oliwer</b>, <b>Oliwier</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Normanowie\" target=\"_blank\" rel=\"noopener noreferrer\">normandzkiego</a>. Wywodzi się od zniekształconego słowa <i>Alfihar</i> oznaczającego „armia elfów”. Z czasem wymowa imienia została zmieniona i zaczęto je wiązać z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a> <i>oliva</i> oznaczającym „drzewo oliwne”. W średniowieczu przybierało ono w Polsce formy <b>Oliwir</b>, <b>Olwir</b>, <b>Olwer</b>. Imię błędnie uznawane za męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Oliwia\" target=\"_blank\" rel=\"noopener noreferrer\">Oliwii</a>.", "Oktawian": "<b>Oktawian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> oznaczające \"członek rzymskiego rodu <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Oktawiusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiuszów</a>\" (ród <i>Octavia</i>). W Polsce imię to pojawiło się dopiero w XIX w..", "Ostap": "<p>Ostap (ukraina: Остап) to ukraińskie imię męskie. Pochodzi od greckiego imienia Eustathius.</p>", "Oleksiy": "<p>Oleksii, Oleksii lub Oleksiĭ (ukrainański: Олексій [olekˈs (j) ij]) to ukraińskie imię męskie pochodzące z starożytnego Grecji.</p>", "Otto": "<b>Otto</b>, <b>Otton</b>, <b>Odo</b>, <b>Odon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. W języku starowysokoniemieckim zapisywano je jako <i>Audo, Odo, Oddo, Oto, Otto, Hotto</i>. Wywodzi się od germańskiego słowa *<i>audha</i> (dziedzictwo, majątek). Mogło być też skróceniem dawnych imion germańskich takich jak <i>Audobercht</i>, <i>Audomar</i>, <a href=\"https://pl.wikipedia.org/wiki/Otmar\" target=\"_blank\" rel=\"noopener noreferrer\">Otmar</a>, <i>Otfried</i>, <a href=\"https://pl.wikipedia.org/wiki/Otokar\" target=\"_blank\" rel=\"noopener noreferrer\">Otokar</a>. Popularne było w średniowieczu, nosiło je wielu cesarzy i książąt niemieckich z dynastii <a href=\"https://pl.wikipedia.org/wiki/Ludolfingowie\" target=\"_blank\" rel=\"noopener noreferrer\">Ludolfingów</a>. W polszczyźnie pojawiło się już u zarania jej dziejów, gdyż w 1000 roku ówczesny książę <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_I_Chrobry\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław</a> nazwał tak swego <a href=\"https://pl.wikipedia.org/wiki/Otto_Boles%C5%82awowic\" target=\"_blank\" rel=\"noopener noreferrer\">syna</a>. W najwcześniejszych zapiskach pojawiały się formy Otto i Oto, później także Hoto i Hotto. Znajdująca się także w użyciu wersja Otton, Odon powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">języka łacińskiego</a> w wyniku <a href=\"https://pl.wikipedia.org/wiki/Fleksja\" target=\"_blank\" rel=\"noopener noreferrer\">odmiany fleksyjnej</a> (analogicznie do np. <a href=\"https://pl.wikipedia.org/wiki/Hugo_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Hugo</a>, Hugon).", "Omer": "<p>Omer może odnosić się do: Omer (jednostka), starożytna jednostka pomiaru używana w czasach starożytnej świątyni w Jerozolimie Liczenie Omer (sefirat ha'omer), 49 dni w kalendarzu żydowskim</p>", "Oktawiusz": "<b>Oktawiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, bezpośrednio pochodzące od nazwy rzymskiego rodu <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Oktawiusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiuszów</a>, dosłownie oznaczające \"ósmy z kolei\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz,_Salwator_i_Adwentor\" target=\"_blank\" rel=\"noopener noreferrer\">św. Oktawiusz</a>, wspominany razem ze <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz,_Salwator_i_Adwentor\" target=\"_blank\" rel=\"noopener noreferrer\">świętymi: Salwatorem i Adwentorem</a>. Żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Oktawia\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawia</a>.", "Oswald": "<b>Oswald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „rządzący z łaski bogów”.", "Osman": "<p>Osman Paşa (1792 - 1860) - turecki wiceadmiral</p>", "Orlando": "<p>Orlando (ang. [ɔːrˈlændoʊ]) - miasto i centrum administracyjne okresu Orange, stanu Florida, USA.</p>", "Ori": "<p>Ori: Ori and the Blind Forest - gra w postaci platformer. Ori and Will of the Wisps - gra wideo-gry platformer, następca Ori and the Blind Forest.</p>", "Otton": "<b>Otto</b>, <b>Otton</b>, <b>Odo</b>, <b>Odon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. W języku starowysokoniemieckim zapisywano je jako <i>Audo, Odo, Oddo, Oto, Otto, Hotto</i>. Wywodzi się od germańskiego słowa *<i>audha</i> (dziedzictwo, majątek). Mogło być też skróceniem dawnych imion germańskich takich jak <i>Audobercht</i>, <i>Audomar</i>, <a href=\"https://pl.wikipedia.org/wiki/Otmar\" target=\"_blank\" rel=\"noopener noreferrer\">Otmar</a>, <i>Otfried</i>, <a href=\"https://pl.wikipedia.org/wiki/Otokar\" target=\"_blank\" rel=\"noopener noreferrer\">Otokar</a>. Popularne było w średniowieczu, nosiło je wielu cesarzy i książąt niemieckich z dynastii <a href=\"https://pl.wikipedia.org/wiki/Ludolfingowie\" target=\"_blank\" rel=\"noopener noreferrer\">Ludolfingów</a>. W polszczyźnie pojawiło się już u zarania jej dziejów, gdyż w 1000 roku ówczesny książę <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_I_Chrobry\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław</a> nazwał tak swego <a href=\"https://pl.wikipedia.org/wiki/Otto_Boles%C5%82awowic\" target=\"_blank\" rel=\"noopener noreferrer\">syna</a>. W najwcześniejszych zapiskach pojawiały się formy Otto i Oto, później także Hoto i Hotto. Znajdująca się także w użyciu wersja Otton, Odon powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">języka łacińskiego</a> w wyniku <a href=\"https://pl.wikipedia.org/wiki/Fleksja\" target=\"_blank\" rel=\"noopener noreferrer\">odmiany fleksyjnej</a> (analogicznie do np. <a href=\"https://pl.wikipedia.org/wiki/Hugo_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Hugo</a>, Hugon).", "Oles": "Zbiorowisko to wytwarzane jest na glebach wytworzonych z <a href=\"https://pl.wikipedia.org/wiki/Torfowisko\" target=\"_blank\" rel=\"noopener noreferrer\">torfowisk</a> niskich, lecz często spotyka się je na <a href=\"https://pl.wikipedia.org/wiki/Gleby_murszowe\" target=\"_blank\" rel=\"noopener noreferrer\">glebach murszowych</a> wytworzonych na <a href=\"https://pl.wikipedia.org/wiki/Piasek\" target=\"_blank\" rel=\"noopener noreferrer\">piaskach</a> i <a href=\"https://pl.wikipedia.org/wiki/Mady\" target=\"_blank\" rel=\"noopener noreferrer\">madach</a> rzecznych, najczęściej są to gleby murszowo-mineralne, murszowe, mulowo-murszowe, torfowo-murszowe, murszowo-glejowe z mullem murszowatym. Dominującą forma <a href=\"https://pl.wikipedia.org/wiki/Pr%C3%B3chnica_(gleba)\" target=\"_blank\" rel=\"noopener noreferrer\">próchnicy</a> typu mull.", "Octavian": "<p>Augustus (lat. Imperator Caesar Divi Filius Augustus; 23 września 63 r. p.n.e. - 19 sierpnia 14 r. n.e.), znany jako Gaius Julius Caesar Octavianus (lat. GAIVS•IVLIVS•CAESAR•OCTAVIANVS, pronounced pronunciation Latin: [au̯ˈɡʊstʊs]), był pierwszym cesarzem Cesarstwa Rzymskiego, rządził od 27 r. p., aż do śmierci w 14 r. p.. Octavian może...</p>", "Owen": "<b>Eugeniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza „zacny“ lub „szlachetnie urodzony”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Eugenia\" target=\"_blank\" rel=\"noopener noreferrer\">Eugenia</a>.", "Onufry": "<b>Onufry</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>onophorbós</i> - pasterz osłów) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>.", "Olexandr": "<p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Oğuzhan": "<p>Oğuzhan jest powszechną męską turską nazwą. \"Oğuzhan\" składa się z dwóch słów, \"Oğüz\" i \"han\"; Oğuz jest nazwiskiem, podczas gdy \"han\" oznacza dosłownie \"khan\".</p>", "Oton": "<p>Oton jest miastem II klasy w prowincji Iloilo, w Filipinach. Według przeprowadzonego w 2000 roku przepisu populacji Philipin, mieście to miało ludności 65,374 osób w 12 907 domach.</p>", "Obinna": "<p>Obinna (ang. Obinna) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Oleksij": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksy</b>.</p><b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Orion": "<b>Orion</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (gr. Ωριων) o nieznanym znaczeniu. Być może wywodzi się ono od gr. <i>‘οριον (horion)</i> — \"granica\". W mitologii greckiej był to <a href=\"https://pl.wikipedia.org/wiki/Orion_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">myśliwy</a>, który zginął od ukąszenia wielkiego skorpiona nasłanego przez boginię łowów <a href=\"https://pl.wikipedia.org/wiki/Artemida\" target=\"_blank\" rel=\"noopener noreferrer\">Artemidę</a> i zamieniony w <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r_Oriona\" target=\"_blank\" rel=\"noopener noreferrer\">konstelację</a>. Patronem tego imienia w Kościele katolickim jest św. Orion, jeden z grupy męczenników z Filippopoli.", "Ollie": "<b>Ollie</b> – jeden z podstawowych trików, jakie można wykonywać na <a href=\"https://pl.wikipedia.org/wiki/Deskorolka\" target=\"_blank\" rel=\"noopener noreferrer\">deskorolce</a>, będący punktem wyjścia wielu innych. W środowisku <a href=\"https://pl.wikipedia.org/wiki/Jazda_na_deskorolce\" target=\"_blank\" rel=\"noopener noreferrer\">skaterów</a> stosuje się termin angielski, bądź nazywa się ten trik \"olka\". Ollie zostało wymyślone przez <a href=\"https://pl.wikipedia.org/wiki/Alan_Gelfand\" target=\"_blank\" rel=\"noopener noreferrer\">Alana Gelfanda</a> w 1979 roku. Ollie to jego drugie imię.", "Ovidiu": "<p>Ovidiu jest miejscowością w hrabstwie Constanța, Rumunii. W 2002 roku liczba ludności wynosiła 13131.</p>", "Otmar": "<b>Otmar</b>, <b>Audomar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone ze starowysokoniemieckich <i>ōt</i>, \"posiadłość, dobrobyt\" i <i>māri</i>, \"sławny\". Imię to było nadawane w Polsce już w średniowieczu. Wśród świętych, <a href=\"https://pl.wikipedia.org/wiki/Otmar_(opat_z_Sankt_Gallen)\" target=\"_blank\" rel=\"noopener noreferrer\">Otmar</a>, <a href=\"https://pl.wikipedia.org/wiki/Opactwo_Sankt_Gallen\" target=\"_blank\" rel=\"noopener noreferrer\">opat w Sankt Gallen</a>.", "Olof": "<p>Olof (niem. Olof) - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Olavi": "<p>Olavi to fińskie imię męskie z imienia Olav/Olaf. Do wybitnych osób z tym nazwiskiem należą: Olavi Ahonen (1923-2000), fiński aktor filmowy Olavi Alakulppi (1915-1990), fiński narciarz krausowy Olavi Hänninen (1920-1992), fiński projektant Joose Olavi Hannula (1900-1944), fiński pułkownik i historyk Olavi Köppä (1951-2025), fiński skater Olavi Kuronen (1923-1989), fiński skaiter narciarz, który rywalizował w...</p>", "Oz": "<p>Oz Oz to język szkoleniowy programowania wysokiego poziomu. Oz (grupa) - fiński heavy-metal-grupa, założona w 1977 roku.</p>", "Oktavian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oktawian</b>.</p><b>Oktawian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> oznaczające \"członek rzymskiego rodu <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Oktawiusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiuszów</a>\" (ród <i>Octavia</i>). W Polsce imię to pojawiło się dopiero w XIX w..", "Orestes": "<b>Orestes</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „góral” (ὄρος <i>oros</i>, „góra”).", "Oleksa": "<p>Oleksa (ukraina: Олекса) jest ukraińskie imię męskie, wariant sławskiej nazwy Alexey lub greckiego Alexius. Nazwa może odnosić się do następujących znaczących osób: Oleksa Dovbush (1700-1745), ukraiński przestępca Oleksa Hirnyk (1912-1978), ukraińska radziecka dysydentka Oleksa Lozowchuk (ur. 1976), kanadyjski kompozytor, producent muzyczny i wieloinstrumentalista Oleksa Novakivskyi (1872-1935), ukraińskiego malarza i nauczyciela sztuki Oleksa Storozhenko...</p>", "Olexiy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksiy</b>.</p><p>Oleksii, Oleksii lub Oleksiĭ (ukrainański: Олексій [olekˈs (j) ij]) to ukraińskie imię męskie pochodzące z starożytnego Grecji.</p>", "Ondrej": "<p>Ondrej jest słowackim imieniem męskim, równoważnym Andrew. Do wybitnych osób z nazwiskiem należą: Ondrej Duda (ur. 1994), sławski piłkarz piłkarza, Ondrej Otčenáš (ur. 1987), sławki hokejista na lodzie, Ondrej Nepela (1951-1989), sławka skaterka na lodzie Ondrej Nepala Arena Ondrej Janík (ur. 1990), sławcki hokejista, Ondrej Zošiak (ur. 1990, obrońca hokeja na lodzie w Słowacji)</p>", "Odil": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Odila</b>.</p><b>Otylia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Otto\" target=\"_blank\" rel=\"noopener noreferrer\">Otto</a> oznaczający „bogatą wojowniczkę” lub „obrończynię bogactwa”. Nosiła je żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wieku</a> mniszka – <a href=\"https://pl.wikipedia.org/wiki/Otylia_z_Hohenburga\" target=\"_blank\" rel=\"noopener noreferrer\">św. Otylia</a>, patronka <a href=\"https://pl.wikipedia.org/wiki/Alzacja\" target=\"_blank\" rel=\"noopener noreferrer\">Alzacji</a>. Alternatywna formy imienia to <i>Odylia</i>.", "Ołeksandr": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksandra</b>.</p><p>Alexandra (w starożytnym greckim ⁇ λεξάνδρα) jest nazwiskiem dla kobiet pochodzącym z Grecji. Jest to pierwsza potwierdzona forma jego wariantów, w tym Aleksandra (starożytny grecki: ⁇ λέξανδρος, Aléxandros).</p>", "Olegi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleg</b>.</p><b>Oleg</b> – rosyjskie imię męskie pochodzenia skandynawskiego (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a>). Występuje ono także w innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach wschodniosłowiańskich</a>, a wywodzi się tam ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroruski\" target=\"_blank\" rel=\"noopener noreferrer\">staroruskiego</a> Ольгъ, zapożyczonego z kolei ze staronordyjskiego <em>Helgi</em> (por. staronorweskie <i>heill</i> „cieszący się pomyślnością, szczęśliwy”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heilig</em> „święty”).", "Om": "<p>Om (czasami stylizowany jako OM) - amerykański stounerowy rock-grupowy z San Francisco, Kalifornia. Zespół powstał jako duet w 2003 roku przez rytm-sekcję zespołu Sleep (basista El Sissneros i perkusista Chris Hakius).</p>", "Otis": "<p>Otis Worldwide Corporation - jedna z najstarszych i największych firm-wyprodukujących sprzęt podnoszący (eskalatory, windy i drogi ruchome). Założona w 1853 roku w Nowym Jorku przez Elise Otis.</p>", "Odo": "<p>Odo, Odon (lat. Odo, Oto, Otto) - imię kilku włoskich muzyków kościelnych i teoretyków muzyki końca X - początku XI wieku.</p>", "Oleksy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksy</b>.</p><b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Olimpiusz": "<b>Olimpiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza \"mieszkaniec <a href=\"https://pl.wikipedia.org/wiki/Olimp\" target=\"_blank\" rel=\"noopener noreferrer\">Olimpu</a>\" lub \"mieszkaniec miasta <a href=\"https://pl.wikipedia.org/wiki/Olimpia\" target=\"_blank\" rel=\"noopener noreferrer\">Olimpia</a>\". Istnieje czterech świętych o tym imieniu.", "Olegs": "<p>Oļegs to imię. Do wybitnych osób z nazwiskiem należą: Oļegs Aleksejenko (ur. 1961), były lotyjski międzynarodowy piłkarz OļegS Antropovs (ur. 1947), lotyjski były piłkarzek siatkówki Oļeg S. Blagonadeždins (ur. 1973), emerytowany obrońca piłki nożnej z Łotwy Oļeg Denizovs (ur., 1966), lotyjski polityk Oļeg Karavajevs (ur. 1961), były lotyjscy bramista piłki noży Oļeg Laizāns (ur. 1987), lotyjskie półbrak...</p>", "Odon": "<b>Otto</b>, <b>Otton</b>, <b>Odo</b>, <b>Odon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. W języku starowysokoniemieckim zapisywano je jako <i>Audo, Odo, Oddo, Oto, Otto, Hotto</i>. Wywodzi się od germańskiego słowa *<i>audha</i> (dziedzictwo, majątek). Mogło być też skróceniem dawnych imion germańskich takich jak <i>Audobercht</i>, <i>Audomar</i>, <a href=\"https://pl.wikipedia.org/wiki/Otmar\" target=\"_blank\" rel=\"noopener noreferrer\">Otmar</a>, <i>Otfried</i>, <a href=\"https://pl.wikipedia.org/wiki/Otokar\" target=\"_blank\" rel=\"noopener noreferrer\">Otokar</a>. Popularne było w średniowieczu, nosiło je wielu cesarzy i książąt niemieckich z dynastii <a href=\"https://pl.wikipedia.org/wiki/Ludolfingowie\" target=\"_blank\" rel=\"noopener noreferrer\">Ludolfingów</a>. W polszczyźnie pojawiło się już u zarania jej dziejów, gdyż w 1000 roku ówczesny książę <a href=\"https://pl.wikipedia.org/wiki/Boles%C5%82aw_I_Chrobry\" target=\"_blank\" rel=\"noopener noreferrer\">Bolesław</a> nazwał tak swego <a href=\"https://pl.wikipedia.org/wiki/Otto_Boles%C5%82awowic\" target=\"_blank\" rel=\"noopener noreferrer\">syna</a>. W najwcześniejszych zapiskach pojawiały się formy Otto i Oto, później także Hoto i Hotto. Znajdująca się także w użyciu wersja Otton, Odon powstała pod wpływem <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">języka łacińskiego</a> w wyniku <a href=\"https://pl.wikipedia.org/wiki/Fleksja\" target=\"_blank\" rel=\"noopener noreferrer\">odmiany fleksyjnej</a> (analogicznie do np. <a href=\"https://pl.wikipedia.org/wiki/Hugo_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Hugo</a>, Hugon).", "Omid": "Szef irańskiej dyplomacji Manuszehr Mottaki zapewnił, że „działalność kosmiczna Iranu ma przeznaczenie wyłącznie pokojowe”. „Nasz potencjał wojskowy ma na celu obronę” – dodał.", "Oran": "<p>Oran (arabski: وهران, Wahrān; berberski: ⵡⴻⵂⵔⴰⵏ) jest miastem północno-zachodnim Algierii, stolicą prowincji Oran, na zachodzie Zatoki Oran (oddział Morza Śródziemnego). Jest to jeden z najbardziej ruchliwych portów, a także centrum handlowego i przemysłowego w kraju.</p>", "Ognyan": "<p>Ognyan (Bulgarski: Огнян) to bułgarskie imię męskie, które może odnosić się do Ognyan Gerdzhikov (ur. 1946), bułgarskiego polityka Ognyan Nikolov (ur. 1949), bułgarskich sportowców Ognyan Toshev (ur. 1940), bułgarańskiego rowerzystę</p>", "Odin": "<p>Jeden: Jeden jest najwyższym bogiem w mitologii niemiecko-skandynawskich. Jedna to najmniejsza liczba naturalna.</p>", "Orestis": "<p>W mytologii greckiej, Orestes lub Orestis (; starożytny grecki: ⁇ ρέστης [oréstɛːs]) był synem Agamemnona z Clytemnestra, bratem Electry, Iphigenia i Chrysothemis.</p>", "Olha": "<p>Olha to ukraińskie imię żeńskie związane z Olgą. Volha to białoruski wariant.</p>", "Olena": "<b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Oluwafemi": "<p>Olúwafẹ́mi to powszechne Nigerię nazwisko niespotykanie z pochodzenia joruba, co oznacza, że Bóg mnie kocha.</p>", "Olumide": "<p>Olumide to zarówno męskie imię, jak i nazwisko. Może odnosić się do: ma znaczenie \"Mój pan przyszedł lub mój bohater przyszedł\".</p>", "Oksana": "<b>Ksenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „gościnna” (Ξενία, dosł. „życzliwa dla obcych”), popularne zwłaszcza w krajach prawosławnych: rosyjskie <b>Ксения</b> (<i><b>Ksienija</b></i>), <b>Аксиния</b> (<i><b>Aksinija</b></i>), ukraińskie <b>Ксенія</b> (<i><b>Ksenija</b></i>), <b>Ксеня</b> (<i><b>Ksenia</b></i>) oraz pochodne <b>Оксана</b> (<i><b>Oksana</b></i>), białoruskie <b>Ксенія</b> (<i><b>Ksenìâ</b></i>), czeskie <b>Xenie</b>, słowackie <b>Xeni</b>.", "Ołeh": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleha</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleh</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleg</b>.</p><b>Oleg</b> – rosyjskie imię męskie pochodzenia skandynawskiego (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a>). Występuje ono także w innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach wschodniosłowiańskich</a>, a wywodzi się tam ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroruski\" target=\"_blank\" rel=\"noopener noreferrer\">staroruskiego</a> Ольгъ, zapożyczonego z kolei ze staronordyjskiego <em>Helgi</em> (por. staronorweskie <i>heill</i> „cieszący się pomyślnością, szczęśliwy”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heilig</em> „święty”).", "Oumar": "<p>Omar jest najczęstszym arabskim tłumaczeniem serii nazw, głównie męskich nazw, pochodzących z języka arabskiego. Nazwa może mieć kilka różnych pisowni w języku angielskim, z różnicami w zależności od oryginalnego języka, z którego pochodzi, regionalnych / kulturowych adaptacji i osobistego wyboru.</p>", "Ozzy": "<p>John Michael \"Ozzy\" Osbourne (ang. John Michael \" Ozzy\" Osborne; 3 grudnia 1948, Marston-Grin, Worrickshire - 22 lipca 2025, Jordans, Buckinghamshire) - angielski piosenkarz, muzykiem.</p>", "Olusegun": "<p>Olusegun (czasami pisane jako Oluwasegun lub jego diminutiwna forma, Segun) jest imieniem pochodzenia joruba dla mężczyzn, co oznacza \"Bóg jest zwycięski\". Znani ludzie z nazwiskiem to: Akinsola Olusegun Faluyi (ur. 1934), nigerijski inżynier Oluseguna Obasanjo (ur. 1937), nigeriński personel wojskowy i polityk Olufela Olusegune Oludotun Ransome-Kuti (1938-1997), lepiej znany jako Fela Kuti, nigerijski muzyk i działacz ds. praw człowieka Olusegún Osoba...</p>", "Oskari": "<p>Oskari to fińskie imię męskie, wariant nazwiska Oscar. Może odnosić się do: Oskari Friman (1893-1933), fiński walczyciel Oskari Frosén (ur. 1976), fiński wysoki skakacz Oskari Mantere (1874-1942), fiński polityk Oskari Mörö (ur. 1993), fiński obstajer Oskari Rissanen (1893-1957), fiński biegacz Oskary Tokoi (1873-1963), fiński politik</p>", "Orson": "<p>Orson to amerykański hollywoodzki zespół rockowy, który istniał w latach 2000-2007. W 2007 roku została laureatem nagrody BRIT Awards w kategorii: Najlepsze międzynarodowe osiągnięcie (Best International Breakthrough Act).</p>", "Oliwiusz": "<b>Oliwiusz</b> — męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Oliwia\" target=\"_blank\" rel=\"noopener noreferrer\">Oliwia</a>, męska forma (łac. <i>Olivius</i>) <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska rodowego (<i>nomen gentilicium</i>)</a> <i>Olivii</i>.", "Olin": "<p>Olin platnicki jest pająkiem z rodziny Trochanteriidae. Roślina ta występuje na Wyspie Święte i Sulawesi.</p>", "Oldřich": "<p>Ołtrzysz (czeski: Oldřich; zmarł 9 listopada 1034) - książę Czechy w latach 1012-1034 z dynastii Prżymysłów.</p>", "Oscar Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Ołeksij": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksy</b>.</p><b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Oleksyi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksy</b>.</p><b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Oron": "<p>Oron jest gminą w Lorraine, w prowincji Moselle, w okręgu Château-Salins, w łódzkim Delme. Poziom geograficzny gmin jest 48° 54' Północna, 06° 28' Wschód.</p>", "Osmar": "<p>Osmar to imię. Osmar Aparecido de Azevedo (ur. 1980), brazylijczyk Osmar Coelho Claudiano (ur. 1982), brazylijski prawy ogon Osmar Donizete Cândido (ur. 1968), brazyliiński piłkarz Osmar Ferreira Júnior (ur. 1987), brazylianki piłkarze Osmar Ferrayra (ur. 1983), argentyński półoczyńca Osmar Ibáñez (ur. 1988), hiszpański piłkerz Osmar Mares (ur. 1987, meksykański...</p>", "Ohanes": "<p>Ohanes jest miastem w prowincji Almería, w autonomicznej społeczności Andaluzji, Hiszpania. Miasto ma powierzchnię 32 km2, liczba ludności w 2005 roku wynosi 795 osób.</p>", "Otokar": "<b>Otokar</b> – imię męskie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzenia germańskiego</a>, złożone z elementów <i>od</i> (zdrowie, dobrobyt) i <i>wakar</i> (czujny, baczny).", "Oscar Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oleksi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksy</b>.</p><b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Olaoluwa": "<p>jest joruba nazwisko dane chłopcu w południowo-zachodniej części Nigerii. \"Ola\", \"Olaolu\" i \"Laolu\" są drobnymi formami nazwy.</p>", "Oluwasegun": "<p>Olusegun (czasami pisane jako Oluwasegun lub jego diminutiwna forma, Segun) jest imieniem pochodzenia joruba dla mężczyzn, co oznacza \"Bóg jest zwycięski\". Znani ludzie z nazwiskiem to: Akinsola Olusegun Faluyi (ur. 1934), nigerijski inżynier Oluseguna Obasanjo (ur. 1937), nigeriński personel wojskowy i polityk Olufela Olusegune Oludotun Ransome-Kuti (1938-1997), lepiej znany jako Fela Kuti, nigerijski muzyk i działacz ds. praw człowieka Olusegún Osoba...</p>", "Oscar Fabian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Omotayo": "<p>Omotayo , to unisex pochodzenia joruba, co oznacza \"dziecko, które przynosi radość\".</p>", "Ottokar": "<b>Otokar</b> – imię męskie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzenia germańskiego</a>, złożone z elementów <i>od</i> (zdrowie, dobrobyt) i <i>wakar</i> (czujny, baczny).", "Odolan": "<b>Odolan</b>, <b>Odolen</b>, <b>Odylen</b> – imię męskie pochodzenia <b><a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a></b>. Pochodzi od słowa: \"(p)odołać\" - <i>oprzeć się, stawić opór, pokonać</i>.", "Obi": "<p>Obi może odnosić się do: Obi (pozycja) Obi (magia)</p>", "Oscar Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Osamu": "<b>Osamu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;おさむ, オサム) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Octave": "<p>Octave: GNU Octave - środowisko do obliczeń liczbowych. Octave to album zespołu The Moody Blues.</p>", "Ovie": "<p>Ovie to imię, pseudonim i nazwisko.</p>", "Oleś": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Olesa</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oles</b>.</p>Zbiorowisko to wytwarzane jest na glebach wytworzonych z <a href=\"https://pl.wikipedia.org/wiki/Torfowisko\" target=\"_blank\" rel=\"noopener noreferrer\">torfowisk</a> niskich, lecz często spotyka się je na <a href=\"https://pl.wikipedia.org/wiki/Gleby_murszowe\" target=\"_blank\" rel=\"noopener noreferrer\">glebach murszowych</a> wytworzonych na <a href=\"https://pl.wikipedia.org/wiki/Piasek\" target=\"_blank\" rel=\"noopener noreferrer\">piaskach</a> i <a href=\"https://pl.wikipedia.org/wiki/Mady\" target=\"_blank\" rel=\"noopener noreferrer\">madach</a> rzecznych, najczęściej są to gleby murszowo-mineralne, murszowe, mulowo-murszowe, torfowo-murszowe, murszowo-glejowe z mullem murszowatym. Dominującą forma <a href=\"https://pl.wikipedia.org/wiki/Pr%C3%B3chnica_(gleba)\" target=\"_blank\" rel=\"noopener noreferrer\">próchnicy</a> typu mull.", "Owais": "<p>Awais (arabski: اویس) lub Owais to arabskie imię, co oznacza \"darzony\" lub \"oddawany\". To było imię jednego z towarzyszy proroka Muhammada Uways al-Qarani.</p>", "Oluwole": "<p>Oluwole - Oba (król) Lagos w latach 1837-1841.</p>", "Otavio": "<p>Otávio to portugalskie imię męskie, odpowiednik angielskiego Octavian, Octavius lub włoski Ottavio. W portugalskich formach Octávio występuje rzadko.</p>", "Ocean": "<p>Ocean - wieloznaczne słowo: Ocean to największy obiekt wodny. Ocean (grek.</p>", "Ozkan": "<p>Özkan to powszechne tureckie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Otávio": "<p>Otávio to portugalskie imię męskie, odpowiednik angielskiego Octavian, Octavius lub włoski Ottavio. W portugalskich formach Octávio występuje rzadko.</p>", "Ozgur": "<p>Özgür jest unisex tureckie nazwisko i nazwisko oznaczające wolne i niezależne. Do wybitnych osób z tym nazwiskiem należą:</p>", "Olov": "<p>Olov (lub Olof) jest szwedzką formą Olav/Olaf, co oznacza \"przedzeń przodków\". Powszechna skróta nazwiska jest Olle.</p>", "Oscar Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Orin": "<p>Or (r) in jest angliczowanym pisownieniem irlandzkiego nazwiska Odhrán, historycznie pisownikiem O ⁇ rán.</p>", "Orjan": "<p>Örjan (OErjan) to staroświeckie imię męskie pochodzące z niskogrzeńskiego Jurian lub Jurien, które jest wariantem George. Dzień Imion w Szwecji to 9 lipca.</p>", "Oscar David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Olatunji": "<p>Olátúnjí jest zarówno nazwiskiem jak i nazwiskiem pochodzenia joruba, co oznacza \"szlachetność/bogacość wskrzesiła, wróciła i staje się silniejsza, jest ponownie potwierdzona\". Krótka forma to Tunji.</p>", "Oscar Mauricio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Onyekachukwu": "<p>Onyekachukwu to męskie imię. Znanymi osobami z nazwiskiem są: Gilbert Onyekachukwu Ibezim (ur. 1978), nigerijski polityk</p>", "Oliwia": "<b>Oliwia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, etymologicznie powiązane z pospolitym wyrazem <i>oliva</i>, „drzewo oliwne, owoc oliwki, oliwka”. Znane było w starożytności. Istnieją dwie patronki tego imienia w <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościele katolickim</a>, jednak właściwe brzmienie ich imienia nie jest pewne – w przypadku jednego z nich Oliwia występuje przemiennie z <b>Oliwą</b>, w innym – z <b>Libią</b> (<a href=\"https://pl.wikipedia.org/wiki/Liba_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Libą</a>) na skutek późnołacińskiej wymowy <i>Olibia</i>. Niektóre źródła wskazują, że jest to imię pochodzenia literackiego, wymyślone przez <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Szekspira</a> na potrzeby komedii <a href=\"https://pl.wikipedia.org/wiki/Wiecz%C3%B3r_Trzech_Kr%C3%B3li\" target=\"_blank\" rel=\"noopener noreferrer\"><i>Wieczór Trzech Króli, lub co chcecie</i></a>.", "Oltion": "<p>Oltion to nazwisko i nazwisko.</p>", "Oladapo": "<p>Oládàpọ̀ (alternatywnie stawiane Ladapo) jest nigerijską nazwą pochodzenia joruba oznaczającą \"kombinację prestiżu, sukcesu i bogactwa została zmieszana razem (podobna) \".</p>", "Oscar Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Ottomar": "<p>Ottomar jest męskim imieniem pochodzenia germańskiego. Pochodzi od Audamar, nazwy składającej się z elementów *aud, co oznacza bogactwo, i *mari, co oznacza sławę.</p>", "Ory": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ori</b>.</p><p>Ori: Ori and the Blind Forest - gra w postaci platformer. Ori and Will of the Wisps - gra wideo-gry platformer, następca Ori and the Blind Forest.</p>", "Oleksandra": "<p>Alexandra (w starożytnym greckim ⁇ λεξάνδρα) jest nazwiskiem dla kobiet pochodzącym z Grecji. Jest to pierwsza potwierdzona forma jego wariantów, w tym Aleksandra (starożytny grecki: ⁇ λέξανδρος, Aléxandros).</p>", "Oliva": "<p>Oliwki (lat. Oliva) - rodzaj morskich żołądkowoogich łupek oddziału Neogastropoda.</p>", "Ozcan": "<p>Özcan to tureckie imię męskie, które pojawia się również jako nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Osagie": "<p>Osagie (zwany również Osaghae, Osaghie, Osaghee i Osaje) jest zarówno nazwiskiem rodzinnym, jak i męskim nazwiskiem pochodzenia nigerijskiego. Jest używany przez Edo i oznacza \"odpowiedź\".</p>", "Oghenetega": "<p>Oghenetega jest unisex nazwisko, ale głównie nadawane do chłopca pochodzącego z Nigerii. Jest nazwany wśród ludności Urhobo w Nigerii.</p>", "Oscar Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Odilon": "<b>Odylon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, urobione od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Otto\" target=\"_blank\" rel=\"noopener noreferrer\">Odo</a>. Jego żeńskim odpowiednikiem jest imię <i>Odile</i>, niefunkcjonujące na gruncie języka polskiego. Wśród <a href=\"https://pl.wikipedia.org/wiki/Patron_(chrze%C5%9Bcija%C5%84stwo)\" target=\"_blank\" rel=\"noopener noreferrer\">patronów</a> <a href=\"https://pl.wikipedia.org/wiki/Odylon_z_Cluny\" target=\"_blank\" rel=\"noopener noreferrer\">św. Odylon</a>, <a href=\"https://pl.wikipedia.org/wiki/Opat\" target=\"_blank\" rel=\"noopener noreferrer\">opat</a> <a href=\"https://pl.wikipedia.org/wiki/Opactwo_%C5%9Bw._Piotra_i_Paw%C5%82a_w_Cluny\" target=\"_blank\" rel=\"noopener noreferrer\">Cluny</a> (zm. <a href=\"https://pl.wikipedia.org/wiki/1049\" target=\"_blank\" rel=\"noopener noreferrer\">1049</a>).", "Olga": "<b>Olga</b> – imię żeńskie, wschodniosłowiański odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Helga\" target=\"_blank\" rel=\"noopener noreferrer\">Helga</a>, pochodzenia skandynawskiego, które wywodzi się od starogermańskiego <i>hails</i> (por. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heil, heilig</em> – zdrowy, szczęśliwy). Na Rusi Kijowskiej stanowi ślad obecności wikińskiej.", "Oday": "<p>Uday lub Odai to męskie imię w języku arabskim, a także w kilku indyjskich językach. W wielu indyjskich językach, w tym hindi, bengalskim, gujaratyjskim, tamilskim i innych, oznacza to \"świt\" lub \"wyłód\".</p>", "Otomar": "<p>Otomar jest czeskim i słowackim imieniem męskim. Do wybitnych osób z tym nazwiskiem należą: Otomar Hájek (1930-2016), czesko-amerykański matematycz Otomar Korbelář (1899-1976), czeski aktor Otomar Krejča (1921-2009), reżyser teatralny i antykomunistyczny disydent Otomar Kubala (1906-1946), słowacki faszyst Otomar Kvěch (1950-2018), czeski kompozytor</p>", "Orly": "<p>Orly to gmina w mieście Paryż, w prowincji Val-de-Marne, francuskiej regionie administracyjnej Île-de-France, z ludnością 20.470 osób (w czasie 1999). Miasto znajduje się w południowej części Paryża, w którym znajduje się port lotniczy Orly.</p>", "Ozer": "<p>Özer składa się z tureckiego öz oznaczającego \"tłocze, istotę\" i er oznacza \"prywatny, żołnierz\". Ozer (Hebrajsky: עוֹזֵר) jest również osobistą nazwą lub nazwiskiem w kulturze żydowskiej.</p>", "Oier": "<p>Oier to męskie baskie imię średniowiecznego pochodzenia. Znaczy \"zniekształcony\". Wchodzi w czołową dziesięć nazw dla chłopców urodzonych w Baskach.</p>", "Olger": "<p>Olger to imię. Do znanych osób z imieniem: Olger B.</p>", "Obaidullah": "<p>Ubayd Allah (arabski: عبيد الله), również pisowany lub przetłumaczony Obaidullah, Obaydullah, Obeidallah lub Ubaydullah, to arabskie imię męskie, które oznacza \"Sługa Boży\".</p>", "Olukayode": "<p>Olukayode jest joruba męskie imię, powszechnie stosowane w Nigerii. W języku joruba oznacza to \"Bóg przynosi szczęście\".</p>", "Olaitan": "<p>Oláìtán (joruba: [ɔ̄láìtã́]; diminutiwna forma Olákìítán) jest zarówno nazwiskiem, jak i unisexnym nazwiskiem pochodzenia joruba oznaczającym \"bogace jest niewyczerpane\" lub \"bogace nigdy nie skończy się\".</p>", "Oscar Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oscar De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Olivo": "<p>Olivo to zarówno hiszpańskie, włoskie, jak i francuskie nazwisko, jak i męskie nazwisko, a także odnosiło się do kogoś, kto uprawiał oliwy. Znani ludzie z nazwiska obejmują: Nazwisko: America Olivo (ur. 1978), amerykańska aktorka i piosenkarka Brock Olivo (urat. 1976), amerykański piłkarz piłkarza Chi-Chi Olivo (1928-1977), amerykańskiego piłkarze baseballu w Republice Dominikańskiej Daniela Olivo (ura. 1989), amerykańca biznesu i profesjonalistę w dziedzinie zdrowia Diomedes Olivo (1919-1977),...</p>", "Olaniyi": "<p>Oláníyì to niżesne nazwisko nigerijskie pochodzenia joruba, oznacza \"Bogotstwo jest szanowane\". Pochodzi z dwóch słów, które są \"Ọlá\" (znaczące bogactwo) i \"Níyì\" (być honorem lub wartością), oba słowa służą również jako demunitywna forma Ọláníyì.</p>", "Oleks": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksa</b>.</p><p>Oleksa (ukraina: Олекса) jest ukraińskie imię męskie, wariant sławskiej nazwy Alexey lub greckiego Alexius. Nazwa może odnosić się do następujących znaczących osób: Oleksa Dovbush (1700-1745), ukraiński przestępca Oleksa Hirnyk (1912-1978), ukraińska radziecka dysydentka Oleksa Lozowchuk (ur. 1976), kanadyjski kompozytor, producent muzyczny i wieloinstrumentalista Oleksa Novakivskyi (1872-1935), ukraińskiego malarza i nauczyciela sztuki Oleksa Storozhenko...</p>", "Odai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oday</b>.</p><p>Uday lub Odai to męskie imię w języku arabskim, a także w kilku indyjskich językach. W wielu indyjskich językach, w tym hindi, bengalskim, gujaratyjskim, tamilskim i innych, oznacza to \"świt\" lub \"wyłód\".</p>", "Obrad": "<p>Obrad (Serbski cyrylski: Обрад) to serbskie męskie imię. Może odnosić się do: Obrad Belošević (1928-1986), serbski sędzia koszykówki Obrad Gluščević (1913-1980), jugosławski reżyser filmowy Obrad Piljak (1933-2013), bosniacki polityk i ekonomista Obrad Stanojević (1934-2011), serbski historyk prawny i profesor Obrad Zelić (ur. 1946), serbski dentysta i profesor Obrat (veliki tepčija), serbski szlachetnik Obrad Dragoslalić, serbski szlaśnik</p>", "Oscar Julian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oleksandr-Yurii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Orlando Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Orlando</b>.</p><p>Orlando (ang. [ɔːrˈlændoʊ]) - miasto i centrum administracyjne okresu Orange, stanu Florida, USA.</p>", "Octav": "<p>Octav to rumuńskie imię męskie, które może odnosić się do: Octav Băncilă (1872-1944), rumuński realistyczny malarz Octav Botez (1884-1943), rumuński krytyk literacki i historyk Octav Botnar (1913-1998), rumuński biznesmen Octav Chelaru (ur. 1991), rumuńskiego reżysera filmowego Octav Cozmâncă (ur. 1947), rumuńczyka polityk Octav Dessila (1895-1976), rumuinskiego pisarza i dramatyk Octav Mayer (1895-1966), rumuinka matematyka Octav Onicescu (1892-1983),...</p>", "Olimpiu": "<p>Olimpiu to rumuńskie imię męskie. Wśród znanych osób z nazwiskiem są: Olimpiu Becheș (ur. 1955), rumuński gracz rugby olimpijski Bucur (ur. 1989), rumuński piłkarz Olimpiu Blaj (ur. 1986), rumuinski aktor Olimpiu Marin (ur. 1969), rumuinski strzelec sportowy Olimpiu Moruțan (ur. 1999), rumuinski piłkarze Olimpiu G.</p>", "Oscar Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oleksandr-Volodymyr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Oscar Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Orlan": "<b>ORLAN</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/30_maja\" target=\"_blank\" rel=\"noopener noreferrer\">30 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1947\" target=\"_blank\" rel=\"noopener noreferrer\">1947</a> w <a href=\"https://pl.wikipedia.org/wiki/Saint-%C3%89tienne\" target=\"_blank\" rel=\"noopener noreferrer\">Saint-Étienne</a> jako <b>Mireille Suzanne Francette Porte</b>) – francuska artystka współczesna. Zajmuje się fotografią, instalacją, rzeźbą, sztuką wideo, performance i in.", "Ovais": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Owais</b>.</p><p>Awais (arabski: اویس) lub Owais to arabskie imię, co oznacza \"darzony\" lub \"oddawany\". To było imię jednego z towarzyszy proroka Muhammada Uways al-Qarani.</p>", "Onni": "<p>Onni to męskie imię pochodzenia fińskiego oznaczające \"szczęście, szczęście\". Było to szóste najpopularniejsze imię dla chłopców w Finlandii w 2007 roku.</p>", "Oldrich": "<p>Oldrich to męskie imię, które może odnosić się do: Oldrich Kotvan (ur. 1990), słowacki hokejista lodu Oldrich Majda (1930-2006), słowacki artysta, malarz, ilustrator i rzeźbiarz Oldřich, lista osób z nazwiskiem</p>", "Oleksandr-Roman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Oluwaferanmi": "<p>Oluwaferanmi to jednoosługa. Znanymi osobami z nazwiska są: Elijah Anuoluwapo Oluwaferanmi Oluwatomi Oluwalana Ayomikulehin Adebayo (ur. 1998), angielski piłkarz Josh Oluwayemi (ur. 2001), angielska piłkarza</p>", "Ostap-Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ostap</b>.</p><p>Ostap (ukraina: Остап) to ukraińskie imię męskie. Pochodzi od greckiego imienia Eustathius.</p>", "Odoardo": "<p>Odoardo to imię. Do wybitnych osób z tym nazwiskiem należą: Odoardo Barri (1844-1920), pseudonim Edwarda Slatera Odoarda Beccari (1843-1920), włoskiego naturalisty, odkrytego w 1878 roku na Sumatrze tytan arum Odoarda Borrani (1833-1905), włoskiej malarza związanego z grupą Macchiaioli Juan Manuel Cajigal yardo Odo (1803-1856), wenezuelskiego matematyka, inżyniera i państwowca Odoarda Farnese (kardynał) (1573-1626), włosk...</p>", "Oluyemi": "<p>Oluyemi to nigeryjska nazwisko niespotykanie z pochodzenia joruba, co oznacza \"Pan jest godny mnie lub Bóg mi pasuje\". Oluyemi to diminutiwna forma imion jorubańskich, takich jak \"Yemi\", co oznacza \"pobić mnie\".</p>", "Oscar Hernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oleksiiy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksiy</b>.</p><p>Oleksii, Oleksii lub Oleksiĭ (ukrainański: Олексій [olekˈs (j) ij]) to ukraińskie imię męskie pochodzące z starożytnego Grecji.</p>", "Orgest": "<p>Orgest to albanska męska nazwa. Wśród znanych osób nosijących nazwę Orgest są: Orgest Buzi (ur. 1994), albanianki piłkarz Orgest Gava (ur. 1990), albanian orgest Serjani (ur. 1988), albanian piłkarza</p>", "Oscar Hernan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Orlando Junior": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Orlando</b>.</p><p>Orlando (ang. [ɔːrˈlændoʊ]) - miasto i centrum administracyjne okresu Orange, stanu Florida, USA.</p>", "Oscar Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Orlando Segundo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Orlando</b>.</p><p>Orlando (ang. [ɔːrˈlændoʊ]) - miasto i centrum administracyjne okresu Orange, stanu Florida, USA.</p>", "Ovadia": "<p>Ovadia lub Ovadya to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą: Dvira Ovadia (ur. 1979), izraelska osobowość telewizyjna i projektant wnętrz Moni Ovadia (1946), włoski aktor, muzyk, piosenkarz i autor teatralny Estreya Haim Ovadya (1922-1944), żydowski partizan Jugosłowiański Robert Ovadia, australijski reporter Ovadia Eli (ur. 1945), izraelski polityk Ovadia Hedaya (1889-1969), izraelska rabina Ovadia Yosef (1918 lub 1920...</p>", "Orlando Rafael": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Orlando</b>.</p><p>Orlando (ang. [ɔːrˈlændoʊ]) - miasto i centrum administracyjne okresu Orange, stanu Florida, USA.</p>", "Oscar Armando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Orlando De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Orlando</b>.</p><p>Orlando (ang. [ɔːrˈlændoʊ]) - miasto i centrum administracyjne okresu Orange, stanu Florida, USA.</p>", "Odilo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Odil</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Odila</b>.</p><b>Otylia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Otto\" target=\"_blank\" rel=\"noopener noreferrer\">Otto</a> oznaczający „bogatą wojowniczkę” lub „obrończynię bogactwa”. Nosiła je żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wieku</a> mniszka – <a href=\"https://pl.wikipedia.org/wiki/Otylia_z_Hohenburga\" target=\"_blank\" rel=\"noopener noreferrer\">św. Otylia</a>, patronka <a href=\"https://pl.wikipedia.org/wiki/Alzacja\" target=\"_blank\" rel=\"noopener noreferrer\">Alzacji</a>. Alternatywna formy imienia to <i>Odylia</i>.", "Oreoluwa": "<p>Oreoluwa to nigeryjska unisex z pochodzenia joruba, co oznacza \"dar od Boga\". Jest podobny w znaczeniu do Olubunmi, Ebunoluwa i Onyinyechi.</p>", "Orlando Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Orlando</b>.</p><p>Orlando (ang. [ɔːrˈlændoʊ]) - miasto i centrum administracyjne okresu Orange, stanu Florida, USA.</p>", "Osip": "<p>Osip (rosyjski: Осип; ukraiński: Осиp), również pisowniany Ossip lub Osyp, jest rosyjską i ukraińską nazwą męską, wariantem nazwiska Józef. Do wybitnych osób z tym nazwiskiem należą: Osip Abdulov (1900-1953), radziecki aktor Osip Aptekman, rosyjski rewolucyjny Ossip Bernstein (1882-1962), ukraińsko-francuski szachowca Osip Bilchansky (1858-1879), rosyjski terroryst powieszony za użycie broni w celu oporu wobec aresztowania Osip Bodyansky'ego (1808-1877), rosyjskie cesarstwo...</p>", "Osorio": "<p>Osorio (zwane również Osório) jest nazwiskiem pochodzącym z Hiszpanii i Portugalii. Do wybitnych osób z tym nazwiskiem należą:</p>", "Osmo": "<p>Osmo to fińskie imię męskie. Występuje w Kalevale, gdzie oznacza \"młody człowiek\".</p>", "Olujimi": "<p>Olújìmí to nigerijskie imię i nazwisko. To męskie imię pochodzące z języka jorubskiego, co oznacza \"Pan mi powierza\".</p>", "Oles-Yurii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oles</b>.</p>Zbiorowisko to wytwarzane jest na glebach wytworzonych z <a href=\"https://pl.wikipedia.org/wiki/Torfowisko\" target=\"_blank\" rel=\"noopener noreferrer\">torfowisk</a> niskich, lecz często spotyka się je na <a href=\"https://pl.wikipedia.org/wiki/Gleby_murszowe\" target=\"_blank\" rel=\"noopener noreferrer\">glebach murszowych</a> wytworzonych na <a href=\"https://pl.wikipedia.org/wiki/Piasek\" target=\"_blank\" rel=\"noopener noreferrer\">piaskach</a> i <a href=\"https://pl.wikipedia.org/wiki/Mady\" target=\"_blank\" rel=\"noopener noreferrer\">madach</a> rzecznych, najczęściej są to gleby murszowo-mineralne, murszowe, mulowo-murszowe, torfowo-murszowe, murszowo-glejowe z mullem murszowatym. Dominującą forma <a href=\"https://pl.wikipedia.org/wiki/Pr%C3%B3chnica_(gleba)\" target=\"_blank\" rel=\"noopener noreferrer\">próchnicy</a> typu mull.", "Otniel": "Pochodził z pokolenia <a href=\"https://pl.wikipedia.org/wiki/Juda_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Judy</a>. Pokonał <a href=\"https://pl.wikipedia.org/wiki/Kuszan-Riszeataim\" target=\"_blank\" rel=\"noopener noreferrer\">Kuszan-Riszeataima</a>, króla <a href=\"https://pl.wikipedia.org/wiki/Aramejczycy\" target=\"_blank\" rel=\"noopener noreferrer\">Aramu</a>, uwalniając tym samym <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izrael</a> z trwającej osiem lat niewoli. Zdobył także miasto Debir należące do <a href=\"https://pl.wikipedia.org/wiki/Kananejczycy\" target=\"_blank\" rel=\"noopener noreferrer\">Kananejczyków</a>, za co otrzymał od <a href=\"https://pl.wikipedia.org/wiki/Kaleb\" target=\"_blank\" rel=\"noopener noreferrer\">Kaleba</a> jego córkę, Aksę za żonę. Po tych wydarzeniach Otniel panował przez 40 lat pokoju. Po jego śmierci lud Izraela znów odstąpił od Boga <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> i został pokonany przez <a href=\"https://pl.wikipedia.org/wiki/Eglon\" target=\"_blank\" rel=\"noopener noreferrer\">Eglona</a>, króla <a href=\"https://pl.wikipedia.org/wiki/Moab\" target=\"_blank\" rel=\"noopener noreferrer\">Moabu</a>.", "Oscar Santiago": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oleksandr-Mykhailo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Oscar Orlando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Orlando Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Orlando</b>.</p><p>Orlando (ang. [ɔːrˈlændoʊ]) - miasto i centrum administracyjne okresu Orange, stanu Florida, USA.</p>", "Oscar Gerardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oleksandr-Andrii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Oleh-Mykhailo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleh</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleg</b>.</p><b>Oleg</b> – rosyjskie imię męskie pochodzenia skandynawskiego (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a>). Występuje ono także w innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach wschodniosłowiańskich</a>, a wywodzi się tam ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroruski\" target=\"_blank\" rel=\"noopener noreferrer\">staroruskiego</a> Ольгъ, zapożyczonego z kolei ze staronordyjskiego <em>Helgi</em> (por. staronorweskie <i>heill</i> „cieszący się pomyślnością, szczęśliwy”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heilig</em> „święty”).", "Oleh-Andriy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleh</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleg</b>.</p><b>Oleg</b> – rosyjskie imię męskie pochodzenia skandynawskiego (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a>). Występuje ono także w innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach wschodniosłowiańskich</a>, a wywodzi się tam ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroruski\" target=\"_blank\" rel=\"noopener noreferrer\">staroruskiego</a> Ольгъ, zapożyczonego z kolei ze staronordyjskiego <em>Helgi</em> (por. staronorweskie <i>heill</i> „cieszący się pomyślnością, szczęśliwy”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heilig</em> „święty”).", "Oscar Uriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oseremen": "<p>Oseremen () to unisex nazwisko pochodzące od ludności Edo w południowej Nigerii. Oznacza to: 'Bóg uczynił dobrze' lub 'Bóg zrobił dobro'.</p>", "Ognian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ognyan</b>.</p><p>Ognyan (Bulgarski: Огнян) to bułgarskie imię męskie, które może odnosić się do Ognyan Gerdzhikov (ur. 1946), bułgarskiego polityka Ognyan Nikolov (ur. 1949), bułgarskich sportowców Ognyan Toshev (ur. 1940), bułgarańskiego rowerzystę</p>", "Orlando Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Orlando</b>.</p><p>Orlando (ang. [ɔːrˈlændoʊ]) - miasto i centrum administracyjne okresu Orange, stanu Florida, USA.</p>", "Otacilio": "<p>Otacílio to portugalska nazwa (czasami nazwisko); może odnosić się do: Otacílio Mariano Neto (ur. 1982), brazylijskiego piłkarza Otacílio Gonçalves (1940-2025), brazylijskiego menedżera piłki nożnej Otacílio Jales da Silva (ur. 1984), brazylii Cilinho, prawdziwe imię Otacílio Pires de Camargo, brazylijski menedżer piłki noży</p>", "Odina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Odin</b>.</p><p>Jeden: Jeden jest najwyższym bogiem w mitologii niemiecko-skandynawskich. Jedna to najmniejsza liczba naturalna.</p>", "Oghenekevwe": "<p>Oghenekevwe to urhobowska nazwisko z południowej Nigerii. Oznacza to \"Bóg dał\", \"Bóg to dał\" lub \"Dar od Boga\".</p>", "Oscar Albeiro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Ostrogniew": "<b>Ostrogniew</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Ostro-</i> (\"ostry\") i <i>-gniew</i> (\"gniew\"). Mogło oznaczać \"tego, którego gniew jest gwałtowny\".", "Oleh-Roman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleh</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleg</b>.</p><b>Oleg</b> – rosyjskie imię męskie pochodzenia skandynawskiego (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a>). Występuje ono także w innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach wschodniosłowiańskich</a>, a wywodzi się tam ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroruski\" target=\"_blank\" rel=\"noopener noreferrer\">staroruskiego</a> Ольгъ, zapożyczonego z kolei ze staronordyjskiego <em>Helgi</em> (por. staronorweskie <i>heill</i> „cieszący się pomyślnością, szczęśliwy”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heilig</em> „święty”).", "Oscar Dario": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Orencjusz": "<b>Orencjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"modlący się\". Istnieje trzech świętych patronów tego imienia.", "Orias": "Zdradza tajemnice gwiazd i domów planetarnych oraz ich znaczenie (naucza <a href=\"https://pl.wikipedia.org/wiki/Astronomia\" target=\"_blank\" rel=\"noopener noreferrer\">astronomii</a> i <a href=\"https://pl.wikipedia.org/wiki/Astrologia\" target=\"_blank\" rel=\"noopener noreferrer\">astrologii</a>). Może nadać człowiekowi dowolny kształt. Rozdaje zaszczyty i tytuły, godzi przyjaciół i wrogów.", "Oleh-Bohdan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleh</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleg</b>.</p><b>Oleg</b> – rosyjskie imię męskie pochodzenia skandynawskiego (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a>). Występuje ono także w innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach wschodniosłowiańskich</a>, a wywodzi się tam ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroruski\" target=\"_blank\" rel=\"noopener noreferrer\">staroruskiego</a> Ольгъ, zapożyczonego z kolei ze staronordyjskiego <em>Helgi</em> (por. staronorweskie <i>heill</i> „cieszący się pomyślnością, szczęśliwy”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heilig</em> „święty”).", "Oscar Felipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oscar Manuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oscar Alonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Osbert": "<p>Osbert to męskie germańskie imię i nazwisko, składające się z elementów ans/os \"bóg\" i berht \"światły\". Może odnosić się do:</p>", "Opher": "<b>Opher</b> – <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">izraelska</a> <a href=\"https://pl.wikipedia.org/wiki/Bomba_kierowana\" target=\"_blank\" rel=\"noopener noreferrer\">bomba kierowana</a> naprowadzana termowizyjnie. Część bojową bomby tworzy izraelska <a href=\"https://pl.wikipedia.org/wiki/Bomba_burz%C4%85ca\" target=\"_blank\" rel=\"noopener noreferrer\">bomba burząca</a> wagomiaru 500 funtów (odpowiednik amerykańskiej <a href=\"https://pl.wikipedia.org/wiki/Mark_82\" target=\"_blank\" rel=\"noopener noreferrer\">Mark 82</a>).", "Octawian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oktawian</b>.</p><b>Oktawian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> oznaczające \"członek rzymskiego rodu <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Oktawiusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiuszów</a>\" (ród <i>Octavia</i>). W Polsce imię to pojawiło się dopiero w XIX w..", "Olivier Nicolas": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olivier</b>.</p><p>Guillaume-Antoine Olivier (francuski: Guillaume - Antoine Olivier, 19 stycznia 1756, Toulon - 1 października 1814, Lyon) - francuski naturalista, botanik, entomolog, zoolog, arachnolog i karcinolog.</p>", "Onezyfor": "<b>Onezyfor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Ονησιφορος</i>, 'Onesiphoros', co oznacza \"przynoszący pożytek, zbawienny, dobroczynny\". Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Onezyfor_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Onezyfor (uczeń św. Pawła)</a>.", "Oscar Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Ousseynou": "<p>Ousseynou to męskie nazwisko afrykańskie, francuska forma arabskiego Hussein. Do wybitnych osób z nazwiskiem należą:</p>", "Oleksandro": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Ollin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Olin</b>.</p><p>Olin platnicki jest pająkiem z rodziny Trochanteriidae. Roślina ta występuje na Wyspie Święte i Sulawesi.</p>", "Oleksandr-Markiian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Oscar Emilio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Olalere": "<p>Olálérè to nigerijskie imię pochodzenia joruba, co oznacza \"bogace jest zyskowne\". Jego diminutiwnym formą są \"Lere\" i \"Ola\".</p>", "Oluremi": "<p>Olúrẹmí to nigeryjskie imię kobiety i pochodzą z joruby, co oznacza \"Pan mnie pociesza\". Olúrẹ̀mí, kiedyś wyłącznie kobiece, jest obecnie przyjmowane przez mężczyzn, odzwierciedlając zmieniające się normy społeczne i rosnący trend nazwisk unisex.</p>", "Oscar Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Oleksii-Mykhailo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleksii</b>.</p><p>Oleksii, Oleksii lub Oleksiĭ (ukrainański: Олексій [olekˈs (j) ij]) to ukraińskie imię męskie pochodzące z starożytnego Grecji.</p>", "Oscar Oswaldo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oscar</b>.</p><p>Oscar (Oscar/Oskar): Oscar - męskie imię.</p>", "Olaff": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Olaf</b>.</p><b>Olaf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Pierwotna forma brzmiała Aslaf. Wywodzi się od słów <i>As</i> (bóg – zobacz <a href=\"https://pl.wikipedia.org/wiki/Azowie\" target=\"_blank\" rel=\"noopener noreferrer\">Asowie</a>) i <i>laf</i> (słowo, które przeszło w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> <i>love</i>), czyli „umiłowany przez bogów”. Inna wersja etymologii głosi, że imię ma znaczenie „syn starego człowieka”.", "Oleh-Pavlo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleh</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleg</b>.</p><b>Oleg</b> – rosyjskie imię męskie pochodzenia skandynawskiego (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a>). Występuje ono także w innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach wschodniosłowiańskich</a>, a wywodzi się tam ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroruski\" target=\"_blank\" rel=\"noopener noreferrer\">staroruskiego</a> Ольгъ, zapożyczonego z kolei ze staronordyjskiego <em>Helgi</em> (por. staronorweskie <i>heill</i> „cieszący się pomyślnością, szczęśliwy”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heilig</em> „święty”).", "Oleksandr-Vasyl": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Olivia": "<p>Olivia Theresa Longott (ur. Olivia Theresa Longot; 15 lutego 1981, Brooklyn, Nowy Jork, USA) - amerykańska piosenkarka.</p>", "Otylia": "<b>Otylia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Otto\" target=\"_blank\" rel=\"noopener noreferrer\">Otto</a> oznaczający „bogatą wojowniczkę” lub „obrończynię bogactwa”. Nosiła je żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wieku</a> mniszka – <a href=\"https://pl.wikipedia.org/wiki/Otylia_z_Hohenburga\" target=\"_blank\" rel=\"noopener noreferrer\">św. Otylia</a>, patronka <a href=\"https://pl.wikipedia.org/wiki/Alzacja\" target=\"_blank\" rel=\"noopener noreferrer\">Alzacji</a>. Alternatywna formy imienia to <i>Odylia</i>.", "Oktawia": "<b>Oktawia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiusz</a>, pochodzącego od rzymskiego rodu <i>Octavia</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Oktawiusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiusze</a>). Patronem tego imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz,_Salwator_i_Adwentor\" target=\"_blank\" rel=\"noopener noreferrer\">św. Oktawiusz</a>, wspominany razem ze świętymi <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz,_Salwator_i_Adwentor\" target=\"_blank\" rel=\"noopener noreferrer\">Salwatorem i Adwentorem</a>.", "Oriana": "<b>Oriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Prawdopodobnie wywodzi się od słowa <i>oro</i> oznaczającego „złoto”. Może też być żeńską odmianą imienia Orjan, które jest skandynawską formą imienia <a href=\"https://pl.wikipedia.org/wiki/Jerzy\" target=\"_blank\" rel=\"noopener noreferrer\">Jerzy</a>. Oriana <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi: <a href=\"https://pl.wikipedia.org/wiki/7_stycznia\" target=\"_blank\" rel=\"noopener noreferrer\">7 stycznia</a>.", "Oryna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Orina</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Orin</b>.</p><p>Or (r) in jest angliczowanym pisownieniem irlandzkiego nazwiska Odhrán, historycznie pisownikiem O ⁇ rán.</p>", "Oliviia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Olivia</b>.</p><p>Olivia Theresa Longott (ur. Olivia Theresa Longot; 15 lutego 1981, Brooklyn, Nowy Jork, USA) - amerykańska piosenkarka.</p>", "Ofelia": "<b>Ofelia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>ophelos</i> oznaczającego „pomoc”. Pierwszy raz użył go <a href=\"https://pl.wikipedia.org/wiki/Jacopo_Sannazaro\" target=\"_blank\" rel=\"noopener noreferrer\">Jacopo Sannazaro</a> w wierszu <i>Arcadia</i>, a spopularyzował <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">William Szekspir</a> w dramacie <a href=\"https://pl.wikipedia.org/wiki/Hamlet\" target=\"_blank\" rel=\"noopener noreferrer\">Hamlet</a>. Jako <i>Ophelia</i> zdobyło pewną popularność w kulturze brytyjskiej.", "Orit": "<p>Orit (אורית) jest hebrajskim imieniem dla kobiet. Znani ludzie z tym nazwiskiem to: Orit Gadiesh Orit Noked Orit Strook Orit Wolf Orit Adato Orit Rozin Orit Bar-On Orit Ishay Orit Zamir Orit Zuaretz Orit Galili-Zucker</p>", "Octavia": "<p>Škoda Octavia - samochód do samochodu z kadą sedan i uniwersal, produkowany w latach 1959-1971. Škoda Octavia - samochód pociągów z kabinami liftback i uniwersal, produkowany od 1996 roku.</p>", "Odetta": "<p>Odetta Holmes (ang. Odetta Holmes; 31 grudnia 1930, Birmingham, Alabama - 2 grudnia 2008, New York) - amerykańska piosenkarka i aktywistka polityczna (bardziej znana jako Odetta), która była uważana za głos walki o prawa obywatelskie (ang.</p>", "Olympia": "<p>Olympia (rosyjski Olympia): W muzyce: Olympia - album Briana Ferry (2010) Olympia - album Austra (2013) Olympia - mini-album The Maybes?</p>", "Odeta": "<b>Odeta</b> − żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a>, południowo-słowiańska forma imienia Odyla – pochodzenia starosaksońskiego, od słowa <i>od</i> (majątek). Oznacza: zamożna.", "Orina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Orin</b>.</p><p>Or (r) in jest angliczowanym pisownieniem irlandzkiego nazwiska Odhrán, historycznie pisownikiem O ⁇ rán.</p>", "Olexandra": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Olexandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Olive": "<p>Olive (z angielskiego - ⁇ Oliwowy ⁇) były brytyjską grupą trip-hop z Londynu.</p>", "Ophelia": "<p>Ophelia (lat. Ophelia) - rodzaj morskich pierścieniowców z klasy Scolecida klasy wieloczęściarzy. Nieznane w skamieniach.</p>", "Oktavia": "<b>Oktawia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiusz</a>, pochodzącego od rzymskiego rodu <i>Octavia</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Oktawiusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiusze</a>). Patronem tego imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz,_Salwator_i_Adwentor\" target=\"_blank\" rel=\"noopener noreferrer\">św. Oktawiusz</a>, wspominany razem ze świętymi <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz,_Salwator_i_Adwentor\" target=\"_blank\" rel=\"noopener noreferrer\">Salwatorem i Adwentorem</a>.", "Oriona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Orion</b>.</p><b>Orion</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (gr. Ωριων) o nieznanym znaczeniu. Być może wywodzi się ono od gr. <i>‘οριον (horion)</i> — \"granica\". W mitologii greckiej był to <a href=\"https://pl.wikipedia.org/wiki/Orion_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">myśliwy</a>, który zginął od ukąszenia wielkiego skorpiona nasłanego przez boginię łowów <a href=\"https://pl.wikipedia.org/wiki/Artemida\" target=\"_blank\" rel=\"noopener noreferrer\">Artemidę</a> i zamieniony w <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r_Oriona\" target=\"_blank\" rel=\"noopener noreferrer\">konstelację</a>. Patronem tego imienia w Kościele katolickim jest św. Orion, jeden z grupy męczenników z Filippopoli.", "Oda": "<b>Oda</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Otto\" target=\"_blank\" rel=\"noopener noreferrer\">Odo</a>. Imię pochodzenia germańskiego, którego podstawę stanowi element od-//ot-, co oznacza „majątek, dziedzictwo, posiadłość, bogactwo”. Starowysokoniemiecka wersja <i>Ute</i> jest obecnie najbardziej popularną formą imienia, choć aż do początku XX wieku była rzadko spotykana. W latach pięćdziesiątych i sześćdziesiątych imię to (w formie Ute) znalazło się kilkukrotnie na liście dziesięciu najpopularniejszych imion żeńskich w Niemczech. Na początku lat siedemdziesiątych jego popularność gwałtownie spadła i obecnie nadawane jest sporadycznie.", "Orla": "<p>Orla jest miastem censusem w Hazaribag w stanie Jharkhand, India.</p>", "Orszula": "<b>Urszula</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Ursula</i>, który stanowi zdrobnienie od wyrazu pospolitego <i>ursa</i> (niedźwiedzica); można je zatem tłumaczyć jako „niedźwiedziczka”. W Polsce imię to notowano od XIV wieku w formie Urszula (od 1367) i Orszula (także od 1367), a także łacińskiej <i>Ursula</i>. Możliwe staropolskie zdrobnienia: Ula; z łac. <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostkiem</a>: Ulita, wschodniosł.: Ulicha. Przez stulecia imię Urszula było rzadkie, a w XIX wieku uchodziło za staromodne i pretensjonalne. Popularność zyskało w XX wieku.", "Oana": "<p>Ioana lub Oana to żeńskie imię pochodzenia rumuńskiego. Jest on równoważny z angielską nazwą Joan, a męska wersja John, wszystkie pochodzące od hebrajskiej nazwy Yohanan.</p>", "Ora": "<p>Ora (chiński: 欧拉; pin'in: Oūlā; stylizowana jako ORA) - chińska marka samochodów elektrycznych Great Wall Motors, przedstawiona w 2018 roku. Według Great Wall Motors, Ora oznacza ⁇ otwarty, niezawodny i alternatywny ⁇ (ang.</p>", "Ołeksandra": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Olexandra</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Olexandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Otilia": "<p>Otilia to kobiece imię. Znanymi osobami z tej nazwy są: Otilia Bădescu (ur. 1970), rumuńska tenisistka tabeli Otilia Brumă (ur. 1992), rumuński piosenkarz-powieściciel Otilia Cazimir (1894-1967), rumuńskiego poety Otilia Larrañaga, meksykańska tancerka i aktorka Otilia Lux, gwatemalska liderka społeczna Otilia Pasarica (ur. 1968), rumuńczyk w siatkówce Otilia Ruicu-Eșanu (ur. 1978), rumuinską atletkę biegów i terenu</p>", "Orianna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oriana</b>.</p><b>Oriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Prawdopodobnie wywodzi się od słowa <i>oro</i> oznaczającego „złoto”. Może też być żeńską odmianą imienia Orjan, które jest skandynawską formą imienia <a href=\"https://pl.wikipedia.org/wiki/Jerzy\" target=\"_blank\" rel=\"noopener noreferrer\">Jerzy</a>. Oriana <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi: <a href=\"https://pl.wikipedia.org/wiki/7_stycznia\" target=\"_blank\" rel=\"noopener noreferrer\">7 stycznia</a>.", "Ofeliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ofelia</b>.</p><b>Ofelia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>ophelos</i> oznaczającego „pomoc”. Pierwszy raz użył go <a href=\"https://pl.wikipedia.org/wiki/Jacopo_Sannazaro\" target=\"_blank\" rel=\"noopener noreferrer\">Jacopo Sannazaro</a> w wierszu <i>Arcadia</i>, a spopularyzował <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">William Szekspir</a> w dramacie <a href=\"https://pl.wikipedia.org/wiki/Hamlet\" target=\"_blank\" rel=\"noopener noreferrer\">Hamlet</a>. Jako <i>Ophelia</i> zdobyło pewną popularność w kulturze brytyjskiej.", "Ozanna": "<b>Ożanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> Osanna, <a href=\"https://pl.wikipedia.org/wiki/Franc.\" target=\"_blank\" rel=\"noopener noreferrer\">franc.</a> Osanne, Ozanne). Wywodzi się z okrzyku hebrajskiego <i>hoszi anna</i>, łac. <i>hosanna</i>, <i>osanna</i> – co oznacza \"daj zbawienie\".", "Ofelya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ofelia</b>.</p><b>Ofelia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>ophelos</i> oznaczającego „pomoc”. Pierwszy raz użył go <a href=\"https://pl.wikipedia.org/wiki/Jacopo_Sannazaro\" target=\"_blank\" rel=\"noopener noreferrer\">Jacopo Sannazaro</a> w wierszu <i>Arcadia</i>, a spopularyzował <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">William Szekspir</a> w dramacie <a href=\"https://pl.wikipedia.org/wiki/Hamlet\" target=\"_blank\" rel=\"noopener noreferrer\">Hamlet</a>. Jako <i>Ophelia</i> zdobyło pewną popularność w kulturze brytyjskiej.", "Oumaima": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oumayma</b>.</p><p>Oumayma, również pisana Umaima, jest arabską nazwą. Znani ludzie z imieniem to: Oumayma Belahbib (ur. 1996), marokański amator boxer Oumayma Ben Maaouia, tunuskiego piłkarza i menedżera Oumayma Dardour (ur. 1996), tunuskiego handbalistki Umaima al-Khamis (ur. 1966), saudyjskiego pisarza</p>", "Olszyna": "<p>Olszyna jest miastem w okręgu Lubański, Dolnośląskie w południowo-zachodniej Polsce. Miasto ma powierzchnię 20 km2.</p>", "Ottilie": "<p>Ottilie to kobiece imię. Jest to francuskie pochodzenie średniowiecznego niemieckiego męskiego imienia Otto i, podobnie jak inne powiązane nazwy germańskie zaczynające się od prefiksów Ad-, Aut-, Od-, Ot-, Oth-, lub Ud-, ma znaczenie \"dobrobyt w bitwie\", \"bogaty\", \"dobrobytu\" lub \"bogaty\".</p>", "Ok": "Zwrot jest pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańskiego</a>, ale jego <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologia</a> nie jest dokładnie znana. Pierwszy raz w druku ukazała się w „The Boston Morning Post”&#65279;<a href=\"https://www.wikidata.org/wiki/Q7719460#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a> 23 marca 1839 roku jako skrót błędnej, ale powszechnej formy <i>all correct</i>. W późnych latach 30. XIX wieku wśród młodszych i lepiej wykształconych <a href=\"https://pl.wikipedia.org/wiki/Amerykan\" target=\"_blank\" rel=\"noopener noreferrer\">Amerykanów</a> pojawiła się praktyka celowego wprowadzania błędów lub skrótów w pisowni niektórych wyrażeń i słów, co przyczyniło się do powstania młodzieżowego slangu. W wyniku tych praktyk powstały takie skróty jak „OK” (wywodzący się z „oll korrect” zamiast „all correct”), „OW” („oll wright” zamiast „all right”) oraz „KY” („know yuse” zamiast „no use”). Tezę tę potwierdza amerykański etymolog i leksykograf Allen Walker Read&#65279;<a href=\"https://www.wikidata.org/wiki/Q384865#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>.", "Oleńka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksandra</b>.</p><b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Oliana": "<p>Oliana jest miastem w \"comarce\"\" Alt Urgell, prowincja Lleida, Katalonia, Hiszpania.</p>", "Ozlem": "<p>Özlem jest powszechną kobiecą turską nazwą. W języku tureckim \"Özlem\" oznacza tęsknienie i zaginięcie.</p>", "Oksanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oksana</b>.</p><b>Ksenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „gościnna” (Ξενία, dosł. „życzliwa dla obcych”), popularne zwłaszcza w krajach prawosławnych: rosyjskie <b>Ксения</b> (<i><b>Ksienija</b></i>), <b>Аксиния</b> (<i><b>Aksinija</b></i>), ukraińskie <b>Ксенія</b> (<i><b>Ksenija</b></i>), <b>Ксеня</b> (<i><b>Ksenia</b></i>) oraz pochodne <b>Оксана</b> (<i><b>Oksana</b></i>), białoruskie <b>Ксенія</b> (<i><b>Ksenìâ</b></i>), czeskie <b>Xenie</b>, słowackie <b>Xeni</b>.", "Olina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Olin</b>.</p><p>Olin platnicki jest pająkiem z rodziny Trochanteriidae. Roślina ta występuje na Wyspie Święte i Sulawesi.</p>", "Oceane": "<p>Océane (w francuskim wymowie: [ɔseˈan]) to francuska nazwisko kobiece, co oznacza \"od oceanu\". Od 2006 roku było dziewiątym najpopularniejszym imieniem dla noworodków we Francji i Quebecu. Wśród znanych osób z tej nazwy są: Océane Avocat Gros (ur. 1997), francuski skakacz narciarski Océane Babel (ur. 2004), francuski tenisa Océane Cassignol (ur. 2000), francuski pływacz Océane Dodin (ur. 1996), francuski tenisista Océane Hurtré (ur. 2004,...</p>", "Ozge": "<p>Özge jest powszechną nazwą turkijską dla kobiet. W języku tureckim \"Özge\" oznacza \"różny\", \"różniony\", \"jedyny\", \"niejasny\" i/lub \"Daredevil\".</p>", "Oleksandrina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Oleksiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksii</b>.</p><p>Oleksii, Oleksii lub Oleksiĭ (ukrainański: Олексій [olekˈs (j) ij]) to ukraińskie imię męskie pochodzące z starożytnego Grecji.</p>", "Olha-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olha</b>.</p><p>Olha to ukraińskie imię żeńskie związane z Olgą. Volha to białoruski wariant.</p>", "Odelia": "<p>Odelia lub Odilia to kobiece imię. Jest to wariantna forma nazwy Ottilie.</p>", "Oleksandryna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Oluwafunmilayo": "<p>Funmi to kobiece imię, które w języku joruba oznacza \"dla mnie\" lub \"oddaj mi\". Jest to diminutiwna wersja nazw takich jak: \"Olufunmilola/Oluwafunmiloła\" (Bóg dał mi bogactwo) lub \"Funmilola\" (daj mi bogactw) \"Olufunmilayo/Oluwa Funfunmilayo\" (Bog mi dał radość) lub \" Funmilayo\" (\"Daj mi radość\").</p>", "Ourania": "Imieniem muzy nazwano jedną z planetoid – <a href=\"https://pl.wikipedia.org/wiki/(30)_Urania\" target=\"_blank\" rel=\"noopener noreferrer\">(30) Urania</a>, niektóre <a href=\"https://pl.wikipedia.org/wiki/Obserwatorium_astronomiczne\" target=\"_blank\" rel=\"noopener noreferrer\">obserwatoria astronomiczne</a> (m.in. w <a href=\"https://pl.wikipedia.org/wiki/Antwerpia\" target=\"_blank\" rel=\"noopener noreferrer\">Antwerpii</a>, <a href=\"https://pl.wikipedia.org/wiki/Berlin\" target=\"_blank\" rel=\"noopener noreferrer\">Berlinie</a>, <a href=\"https://pl.wikipedia.org/wiki/Wiede%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">Wiedniu</a>, <a href=\"https://pl.wikipedia.org/wiki/Zurych\" target=\"_blank\" rel=\"noopener noreferrer\">Zurychu</a>) oraz czasopismo poświęcone upowszechnianiu wiedzy astronomicznej – „<a href=\"https://pl.wikipedia.org/wiki/Urania_%E2%80%93_Post%C4%99py_Astronomii\" target=\"_blank\" rel=\"noopener noreferrer\">Urania – Postępy Astronomii</a>”, a także nocny pociąg TLK Urania, w sezonie letnim 2016, kursujący między Krakowem a Kołobrzegiem i Krakowem a Ustką.", "Oriiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oriana</b>.</p><b>Oriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Prawdopodobnie wywodzi się od słowa <i>oro</i> oznaczającego „złoto”. Może też być żeńską odmianą imienia Orjan, które jest skandynawską formą imienia <a href=\"https://pl.wikipedia.org/wiki/Jerzy\" target=\"_blank\" rel=\"noopener noreferrer\">Jerzy</a>. Oriana <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi: <a href=\"https://pl.wikipedia.org/wiki/7_stycznia\" target=\"_blank\" rel=\"noopener noreferrer\">7 stycznia</a>.", "Oumayma": "<p>Oumayma, również pisana Umaima, jest arabską nazwą. Znani ludzie z imieniem to: Oumayma Belahbib (ur. 1996), marokański amator boxer Oumayma Ben Maaouia, tunuskiego piłkarza i menedżera Oumayma Dardour (ur. 1996), tunuskiego handbalistki Umaima al-Khamis (ur. 1966), saudyjskiego pisarza</p>", "Owidia": "<b>Owidia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od łac. nazwy rodowej, która z kolei być może pochodzi od łac. słowa <i>ovis</i> — \"owieczka\", albo też ma pochodzenie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_oskijsko-umbryjskie\" target=\"_blank\" rel=\"noopener noreferrer\">oskijsko-umbryjskie</a>. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Owidiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Owidiusz</a>. Patronem tego imienia w <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościele katolickim</a> jest św. Owidiusz, biskup w <a href=\"https://pl.wikipedia.org/wiki/Galia\" target=\"_blank\" rel=\"noopener noreferrer\">Galii</a>.", "Orjana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Orjan</b>.</p><p>Örjan (OErjan) to staroświeckie imię męskie pochodzące z niskogrzeńskiego Jurian lub Jurien, które jest wariantem George. Dzień Imion w Szwecji to 9 lipca.</p>", "Oleksandra-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleksandra</b>.</p><p>Alexandra (w starożytnym greckim ⁇ λεξάνδρα) jest nazwiskiem dla kobiet pochodzącym z Grecji. Jest to pierwsza potwierdzona forma jego wariantów, w tym Aleksandra (starożytny grecki: ⁇ λέξανδρος, Aléxandros).</p>", "Ottylia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Otylia</b>.</p><b>Otylia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Otto\" target=\"_blank\" rel=\"noopener noreferrer\">Otto</a> oznaczający „bogatą wojowniczkę” lub „obrończynię bogactwa”. Nosiła je żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wieku</a> mniszka – <a href=\"https://pl.wikipedia.org/wiki/Otylia_z_Hohenburga\" target=\"_blank\" rel=\"noopener noreferrer\">św. Otylia</a>, patronka <a href=\"https://pl.wikipedia.org/wiki/Alzacja\" target=\"_blank\" rel=\"noopener noreferrer\">Alzacji</a>. Alternatywna formy imienia to <i>Odylia</i>.", "Olesa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oles</b>.</p>Zbiorowisko to wytwarzane jest na glebach wytworzonych z <a href=\"https://pl.wikipedia.org/wiki/Torfowisko\" target=\"_blank\" rel=\"noopener noreferrer\">torfowisk</a> niskich, lecz często spotyka się je na <a href=\"https://pl.wikipedia.org/wiki/Gleby_murszowe\" target=\"_blank\" rel=\"noopener noreferrer\">glebach murszowych</a> wytworzonych na <a href=\"https://pl.wikipedia.org/wiki/Piasek\" target=\"_blank\" rel=\"noopener noreferrer\">piaskach</a> i <a href=\"https://pl.wikipedia.org/wiki/Mady\" target=\"_blank\" rel=\"noopener noreferrer\">madach</a> rzecznych, najczęściej są to gleby murszowo-mineralne, murszowe, mulowo-murszowe, torfowo-murszowe, murszowo-glejowe z mullem murszowatym. Dominującą forma <a href=\"https://pl.wikipedia.org/wiki/Pr%C3%B3chnica_(gleba)\" target=\"_blank\" rel=\"noopener noreferrer\">próchnicy</a> typu mull.", "Omolara": "<p>Omolara to nazwisko kobiety z Nigerii pochodzące z języka jorubskiego, które tłumaczy \"dziecko jest krewnym\". Nazwa ta rozszerza się również w wierze joruba, co oznacza, że \"dziecko jest najbardziej wiarygodnym krewnym\".</p>", "Oznur": "<p>Öznur to tureckie imię dla kobiet. Znanymi osobami z nazwiska są: Öznur Cüre (ur. 1997), turecki pałacowiec paraolimpijski Öznur Kızıl (ur. 1991), turecki praktyk wushu Öznur Polat (ur. 1987), turecki curler i trener kurlingu Öznur Serçeler (ur. 1987, turka aktorka</p>", "Oliwiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oliwia</b>.</p><b>Oliwia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, etymologicznie powiązane z pospolitym wyrazem <i>oliva</i>, „drzewo oliwne, owoc oliwki, oliwka”. Znane było w starożytności. Istnieją dwie patronki tego imienia w <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościele katolickim</a>, jednak właściwe brzmienie ich imienia nie jest pewne – w przypadku jednego z nich Oliwia występuje przemiennie z <b>Oliwą</b>, w innym – z <b>Libią</b> (<a href=\"https://pl.wikipedia.org/wiki/Liba_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Libą</a>) na skutek późnołacińskiej wymowy <i>Olibia</i>. Niektóre źródła wskazują, że jest to imię pochodzenia literackiego, wymyślone przez <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Szekspira</a> na potrzeby komedii <a href=\"https://pl.wikipedia.org/wiki/Wiecz%C3%B3r_Trzech_Kr%C3%B3li\" target=\"_blank\" rel=\"noopener noreferrer\"><i>Wieczór Trzech Króli, lub co chcecie</i></a>.", "Ottavia": "<p>Ottavia (/otˈta.vja/) jest łacińskim pochodzeniem imieniem kobiece. Jest to kobieca wersja Ottavio i ma wariant, Ottaviana.</p>", "Olha-Viktoriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olha</b>.</p><p>Olha to ukraińskie imię żeńskie związane z Olgą. Volha to białoruski wariant.</p>", "Oona": "<p>Oona to kobiece imię. Jest angielsko pojęciem irlandzkiego imienia Úna.</p>", "Oktaviia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oktavia</b>.</p><b>Oktawia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiusz</a>, pochodzącego od rzymskiego rodu <i>Octavia</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Oktawiusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiusze</a>). Patronem tego imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz,_Salwator_i_Adwentor\" target=\"_blank\" rel=\"noopener noreferrer\">św. Oktawiusz</a>, wspominany razem ze świętymi <a href=\"https://pl.wikipedia.org/wiki/Oktawiusz,_Salwator_i_Adwentor\" target=\"_blank\" rel=\"noopener noreferrer\">Salwatorem i Adwentorem</a>.", "Olga Lucia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olga</b>.</p><b>Olga</b> – imię żeńskie, wschodniosłowiański odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Helga\" target=\"_blank\" rel=\"noopener noreferrer\">Helga</a>, pochodzenia skandynawskiego, które wywodzi się od starogermańskiego <i>hails</i> (por. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heil, heilig</em> – zdrowy, szczęśliwy). Na Rusi Kijowskiej stanowi ślad obecności wikińskiej.", "Olgierda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Olgierd</b>.</p><b>Olgierd</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Litwa\" target=\"_blank\" rel=\"noopener noreferrer\">litewskiego</a> (po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> <i>Algirdas</i>). Jego drugi człon łączony jest z lit. czasownikiem <i>girti</i> – „chwalić, sławić”; pierwszy człon, <i>Al-</i>, jest niejasny&#8201;, jednak niektórzy badacze dopatrują się w nim odpowiednika <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a> <i>al</i> – „cały, wszystek”, na podstawie podobieństwa do lit. <i>aliai</i> – „każdy”; Olgierd (<i>Algirdas</i>) oznaczałoby wówczas „wszystek sławny”, „przesławny”&#8201;. Jako imię chrzestne <b>Olgierd</b> pojawia się w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>, na początku w litewskich rodach arystokratycznych, przypuszczalnie nie bez związku z powieścią historyczną <a href=\"https://pl.wikipedia.org/wiki/Alexander_von_Oppeln-Bronikowski\" target=\"_blank\" rel=\"noopener noreferrer\">A. Bronikowskiego</a> „<i>Olgierd i <a href=\"https://pl.wikipedia.org/wiki/Olga\" target=\"_blank\" rel=\"noopener noreferrer\">Olga</a> czyli Polska w jedenastym wieku</i>” (1828)&#8201;.", "Orlaith": "<p>Órlaith (OR-lə; również pisane Órfhlaith lub Órla) to żeńskie irlandzkie imię. Znaczenie nazwy pochodzi z irlandzkiego słowa ór \"złoty\" i flaith \"księcia\", chociaż ponieważ nazwy utworzone z \"flaith\" są prawie wyłącznie kobiece, zazwyczaj jest interpretowane jako oznacza \"księżniczka\".</p>", "Oleksandra-Sofiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleksandra</b>.</p><p>Alexandra (w starożytnym greckim ⁇ λεξάνδρα) jest nazwiskiem dla kobiet pochodzącym z Grecji. Jest to pierwsza potwierdzona forma jego wariantów, w tym Aleksandra (starożytny grecki: ⁇ λέξανδρος, Aléxandros).</p>", "Olga Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olga</b>.</p><b>Olga</b> – imię żeńskie, wschodniosłowiański odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Helga\" target=\"_blank\" rel=\"noopener noreferrer\">Helga</a>, pochodzenia skandynawskiego, które wywodzi się od starogermańskiego <i>hails</i> (por. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heil, heilig</em> – zdrowy, szczęśliwy). Na Rusi Kijowskiej stanowi ślad obecności wikińskiej.", "Olena-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olena</b>.</p><b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Olea": "<b>Oliwka</b> (<i>Olea</i> <a href=\"https://pl.wikipedia.org/wiki/Karol_Linneusz\" target=\"_blank\" rel=\"noopener noreferrer\">L.</a>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> drzew należący do rodziny <a href=\"https://pl.wikipedia.org/wiki/Oliwkowate\" target=\"_blank\" rel=\"noopener noreferrer\">oliwkowatych</a>. Zalicza się do niego 12 gatunków, choć dawniej dzielono rodzaj nawet na ponad 30 gatunków. Są to zimozielone <a href=\"https://pl.wikipedia.org/wiki/Drzewo\" target=\"_blank\" rel=\"noopener noreferrer\">drzewa</a> i <a href=\"https://pl.wikipedia.org/wiki/Krzew\" target=\"_blank\" rel=\"noopener noreferrer\">krzewy</a>. Rosną w strefie międzyzwrotnikowej i w ciepłym klimacie umiarkowanym południowej <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europy</a>, <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>, południowej <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">Azji</a> i <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australii</a>. Największe znaczenie użytkowe ma <a href=\"https://pl.wikipedia.org/wiki/Oliwka_europejska\" target=\"_blank\" rel=\"noopener noreferrer\">oliwka europejska</a>, z której owoców pozyskuje się <a href=\"https://pl.wikipedia.org/wiki/Olej_oliwkowy\" target=\"_blank\" rel=\"noopener noreferrer\">oliwę</a>. Gatunek ten i kilka innych z rodzaju (<i>O. capensis, O. welwitschii</i>) dostarcza cenionego, bardzo twardego <a href=\"https://pl.wikipedia.org/wiki/Drewno_(technika)\" target=\"_blank\" rel=\"noopener noreferrer\">drewna</a> (zaliczane są one do tzw. <a href=\"https://pl.wikipedia.org/wiki/Drzewo_%C5%BCelazne\" target=\"_blank\" rel=\"noopener noreferrer\">drzew żelaznych</a>).", "Oana-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oana</b>.</p><p>Ioana lub Oana to żeńskie imię pochodzenia rumuńskiego. Jest on równoważny z angielską nazwą Joan, a męska wersja John, wszystkie pochodzące od hebrajskiej nazwy Yohanan.</p>", "Oliwiera": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oliwier</b>.</p><b>Oliwer</b>, <b>Oliwier</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Normanowie\" target=\"_blank\" rel=\"noopener noreferrer\">normandzkiego</a>. Wywodzi się od zniekształconego słowa <i>Alfihar</i> oznaczającego „armia elfów”. Z czasem wymowa imienia została zmieniona i zaczęto je wiązać z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a> <i>oliva</i> oznaczającym „drzewo oliwne”. W średniowieczu przybierało ono w Polsce formy <b>Oliwir</b>, <b>Olwir</b>, <b>Olwer</b>. Imię błędnie uznawane za męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Oliwia\" target=\"_blank\" rel=\"noopener noreferrer\">Oliwii</a>.", "Opal": "<b>Opal</b> – <a href=\"https://pl.wikipedia.org/wiki/Mineraloid\" target=\"_blank\" rel=\"noopener noreferrer\">mineraloid</a> zaliczany do <a href=\"https://pl.wikipedia.org/wiki/Krzemiany\" target=\"_blank\" rel=\"noopener noreferrer\">krzemianów</a>. Nazwa pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckiego</a> <i>upala</i> = drogi kamień, kamień szlachetny; bądź od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>opallios (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> opalus)</i> = widzieć zmianę (barwy). Opal jest oficjalnym <a href=\"https://pl.wikipedia.org/wiki/Kamienie_szlachetne\" target=\"_blank\" rel=\"noopener noreferrer\">kamieniem szlachetnym</a> <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australii</a>.", "Oonagh": "<p>Oona to kobiece imię. Jest angielsko pojęciem irlandzkiego imienia Úna.</p>", "Olha-Iryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olha</b>.</p><p>Olha to ukraińskie imię żeńskie związane z Olgą. Volha to białoruski wariant.</p>", "Oliwera": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oliwer</b>.</p><b>Oliwer</b>, <b>Oliwier</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Normanowie\" target=\"_blank\" rel=\"noopener noreferrer\">normandzkiego</a>. Wywodzi się od zniekształconego słowa <i>Alfihar</i> oznaczającego „armia elfów”. Z czasem wymowa imienia została zmieniona i zaczęto je wiązać z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a> <i>oliva</i> oznaczającym „drzewo oliwne”. W średniowieczu przybierało ono w Polsce formy <b>Oliwir</b>, <b>Olwir</b>, <b>Olwer</b>. Imię błędnie uznawane za męski odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Oliwia\" target=\"_blank\" rel=\"noopener noreferrer\">Oliwii</a>.", "Oleksandra-Viktoriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oleksandra</b>.</p><p>Alexandra (w starożytnym greckim ⁇ λεξάνδρα) jest nazwiskiem dla kobiet pochodzącym z Grecji. Jest to pierwsza potwierdzona forma jego wariantów, w tym Aleksandra (starożytny grecki: ⁇ λέξανδρος, Aléxandros).</p>", "Odilla": "<b>Otylia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Otto\" target=\"_blank\" rel=\"noopener noreferrer\">Otto</a> oznaczający „bogatą wojowniczkę” lub „obrończynię bogactwa”. Nosiła je żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wieku</a> mniszka – <a href=\"https://pl.wikipedia.org/wiki/Otylia_z_Hohenburga\" target=\"_blank\" rel=\"noopener noreferrer\">św. Otylia</a>, patronka <a href=\"https://pl.wikipedia.org/wiki/Alzacja\" target=\"_blank\" rel=\"noopener noreferrer\">Alzacji</a>. Alternatywna formy imienia to <i>Odylia</i>.", "Olha-Yuliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olha</b>.</p><p>Olha to ukraińskie imię żeńskie związane z Olgą. Volha to białoruski wariant.</p>", "Oceana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ocean</b>.</p><p>Ocean - wieloznaczne słowo: Ocean to największy obiekt wodny. Ocean (grek.</p>", "Olga Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olga</b>.</p><b>Olga</b> – imię żeńskie, wschodniosłowiański odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Helga\" target=\"_blank\" rel=\"noopener noreferrer\">Helga</a>, pochodzenia skandynawskiego, które wywodzi się od starogermańskiego <i>hails</i> (por. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heil, heilig</em> – zdrowy, szczęśliwy). Na Rusi Kijowskiej stanowi ślad obecności wikińskiej.", "Olijana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oliana</b>.</p><p>Oliana jest miastem w \"comarce\"\" Alt Urgell, prowincja Lleida, Katalonia, Hiszpania.</p>", "Ofka": "<b>Eufemia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Złożone jest z elementów εὐ- („dobry”) i φήμη („wróżba”), i oznacza „dobrze wróżąca”, „pomyślnie wróżąca”, „przychylna”. W Polsce imię to zanotowano w XIII wieku. Nosiły je m.in. księżniczki piastowskie. Imię zdrabniano jako Ofka.", "Omega": "Nazwa tej litery oznacza dosłownie „o” wielkie (<i>mega</i> = <i>duży, wielki</i>) w odróżnieniu od „ο” małego, czyli <a href=\"https://pl.wikipedia.org/wiki/Omikron\" target=\"_blank\" rel=\"noopener noreferrer\">omikron</a>. Nazwy obydwu liter są pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Bizanty%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">bizantyjskiego</a>. <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytna_Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">Starożytni Grecy</a> nazywali omegę po prostu „o”, zaś nazwę omikron wymawiali „ou”. Kształt <a href=\"https://pl.wikipedia.org/wiki/Majusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">majuskuły</a>, czyli wielkiej litery omega jest formą <a href=\"https://pl.wikipedia.org/wiki/Okr%C4%85g\" target=\"_blank\" rel=\"noopener noreferrer\">okręgu</a> otwartego u dołu z zawiniętymi końcami (czasem kanciasto, czasem okrągło). Bywa też zapisywana w formie pełnego okręgu z szeroką kreską u dołu. <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">Minuskuła</a>, czyli mała litera wykształciła się z podwójnej małej litery „ο”, która uzyskała z czasem otwarcie od góry.", "Ok Ju": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ok</b>.</p>Zwrot jest pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańskiego</a>, ale jego <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologia</a> nie jest dokładnie znana. Pierwszy raz w druku ukazała się w „The Boston Morning Post”&#65279;<a href=\"https://www.wikidata.org/wiki/Q7719460#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a> 23 marca 1839 roku jako skrót błędnej, ale powszechnej formy <i>all correct</i>. W późnych latach 30. XIX wieku wśród młodszych i lepiej wykształconych <a href=\"https://pl.wikipedia.org/wiki/Amerykan\" target=\"_blank\" rel=\"noopener noreferrer\">Amerykanów</a> pojawiła się praktyka celowego wprowadzania błędów lub skrótów w pisowni niektórych wyrażeń i słów, co przyczyniło się do powstania młodzieżowego slangu. W wyniku tych praktyk powstały takie skróty jak „OK” (wywodzący się z „oll korrect” zamiast „all correct”), „OW” („oll wright” zamiast „all right”) oraz „KY” („know yuse” zamiast „no use”). Tezę tę potwierdza amerykański etymolog i leksykograf Allen Walker Read&#65279;<a href=\"https://www.wikidata.org/wiki/Q384865#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>.", "Orlana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Orlan</b>.</p><b>ORLAN</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/30_maja\" target=\"_blank\" rel=\"noopener noreferrer\">30 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1947\" target=\"_blank\" rel=\"noopener noreferrer\">1947</a> w <a href=\"https://pl.wikipedia.org/wiki/Saint-%C3%89tienne\" target=\"_blank\" rel=\"noopener noreferrer\">Saint-Étienne</a> jako <b>Mireille Suzanne Francette Porte</b>) – francuska artystka współczesna. Zajmuje się fotografią, instalacją, rzeźbą, sztuką wideo, performance i in.", "Okuhle": "<p>Okuhle to imię Nguni, które oznacza \"to, co jest piękne\" lub \"to, które jest dobre. Znani ludzie z nazwiskiem to: Okuhle Cele (ur. 1997), gracz kryketowy Okuhle Dlamini, królowa piękności Południowej Afryki, Little Miss Południe Afryki 2025 Aphelele Onke Okuhle Fassi (ur. 1998), gracz rugby po południowej afryce</p>", "Olivia-Alexandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olivia</b>.</p><p>Olivia Theresa Longott (ur. Olivia Theresa Longot; 15 lutego 1981, Brooklyn, Nowy Jork, USA) - amerykańska piosenkarka.</p>", "Oksana-Snizhana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oksana</b>.</p><b>Ksenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „gościnna” (Ξενία, dosł. „życzliwa dla obcych”), popularne zwłaszcza w krajach prawosławnych: rosyjskie <b>Ксения</b> (<i><b>Ksienija</b></i>), <b>Аксиния</b> (<i><b>Aksinija</b></i>), ukraińskie <b>Ксенія</b> (<i><b>Ksenija</b></i>), <b>Ксеня</b> (<i><b>Ksenia</b></i>) oraz pochodne <b>Оксана</b> (<i><b>Oksana</b></i>), białoruskie <b>Ксенія</b> (<i><b>Ksenìâ</b></i>), czeskie <b>Xenie</b>, słowackie <b>Xeni</b>.", "Ok Gyong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ok</b>.</p>Zwrot jest pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańskiego</a>, ale jego <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologia</a> nie jest dokładnie znana. Pierwszy raz w druku ukazała się w „The Boston Morning Post”&#65279;<a href=\"https://www.wikidata.org/wiki/Q7719460#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a> 23 marca 1839 roku jako skrót błędnej, ale powszechnej formy <i>all correct</i>. W późnych latach 30. XIX wieku wśród młodszych i lepiej wykształconych <a href=\"https://pl.wikipedia.org/wiki/Amerykan\" target=\"_blank\" rel=\"noopener noreferrer\">Amerykanów</a> pojawiła się praktyka celowego wprowadzania błędów lub skrótów w pisowni niektórych wyrażeń i słów, co przyczyniło się do powstania młodzieżowego slangu. W wyniku tych praktyk powstały takie skróty jak „OK” (wywodzący się z „oll korrect” zamiast „all correct”), „OW” („oll wright” zamiast „all right”) oraz „KY” („know yuse” zamiast „no use”). Tezę tę potwierdza amerykański etymolog i leksykograf Allen Walker Read&#65279;<a href=\"https://www.wikidata.org/wiki/Q384865#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>.", "Ortrud": "<p>Ortrud to kobiece imię, z wariantami Ortraud i Ortrude. Ortrud może odnosić się do: Ortrud, postać w operze Richarda Wagnera Lohengrin Ortrud Beginnen (1938-1999), niemiecka aktorka filmowa Ortrud Mavrin, postać we drugiej powieści Anthony'ego Powella Venusberg (1932) Ortrud Oellermann (aktywny od 1981 roku), południowoafrykański matematycz 551 Ortrud , asteroida z głównym pasem</p>", "Orijana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oriana</b>.</p><b>Oriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a>. Prawdopodobnie wywodzi się od słowa <i>oro</i> oznaczającego „złoto”. Może też być żeńską odmianą imienia Orjan, które jest skandynawską formą imienia <a href=\"https://pl.wikipedia.org/wiki/Jerzy\" target=\"_blank\" rel=\"noopener noreferrer\">Jerzy</a>. Oriana <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi: <a href=\"https://pl.wikipedia.org/wiki/7_stycznia\" target=\"_blank\" rel=\"noopener noreferrer\">7 stycznia</a>.", "Olgica": "<p>Olgica to kobiece imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Oleksia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleksy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksy</b>.</p><b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Olha-Karina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olha</b>.</p><p>Olha to ukraińskie imię żeńskie związane z Olgą. Volha to białoruski wariant.</p>", "Otiliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Otilia</b>.</p><p>Otilia to kobiece imię. Znanymi osobami z tej nazwy są: Otilia Bădescu (ur. 1970), rumuńska tenisistka tabeli Otilia Brumă (ur. 1992), rumuński piosenkarz-powieściciel Otilia Cazimir (1894-1967), rumuńskiego poety Otilia Larrañaga, meksykańska tancerka i aktorka Otilia Lux, gwatemalska liderka społeczna Otilia Pasarica (ur. 1968), rumuńczyk w siatkówce Otilia Ruicu-Eșanu (ur. 1978), rumuinską atletkę biegów i terenu</p>", "Oghenefejiro": "<p>Oghenefejiro jest powszechną nazwą wśród ludności Urhobo w Nigerii. To unisexne imię, które oznacza \"Bóg jest godny chwał\" lub \"Bóg zasługuje na chwałę\".</p>", "Otoha": "<b>Otoha</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;(おとは, オトハ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Odila": "<b>Otylia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Otto\" target=\"_blank\" rel=\"noopener noreferrer\">Otto</a> oznaczający „bogatą wojowniczkę” lub „obrończynię bogactwa”. Nosiła je żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wieku</a> mniszka – <a href=\"https://pl.wikipedia.org/wiki/Otylia_z_Hohenburga\" target=\"_blank\" rel=\"noopener noreferrer\">św. Otylia</a>, patronka <a href=\"https://pl.wikipedia.org/wiki/Alzacja\" target=\"_blank\" rel=\"noopener noreferrer\">Alzacji</a>. Alternatywna formy imienia to <i>Odylia</i>.", "Olivia-Rose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olivia</b>.</p><p>Olivia Theresa Longott (ur. Olivia Theresa Longot; 15 lutego 1981, Brooklyn, Nowy Jork, USA) - amerykańska piosenkarka.</p>", "Oleha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleh</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oleg</b>.</p><b>Oleg</b> – rosyjskie imię męskie pochodzenia skandynawskiego (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a>). Występuje ono także w innych <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_wschodnios%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">językach wschodniosłowiańskich</a>, a wywodzi się tam ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroruski\" target=\"_blank\" rel=\"noopener noreferrer\">staroruskiego</a> Ольгъ, zapożyczonego z kolei ze staronordyjskiego <em>Helgi</em> (por. staronorweskie <i>heill</i> „cieszący się pomyślnością, szczęśliwy”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>heilig</em> „święty”).", "Órfhlaith": "<p>Órlaith (OR-lə; również pisane Órfhlaith lub Órla) to żeńskie irlandzkie imię. Znaczenie nazwy pochodzi z irlandzkiego słowa ór \"złoty\" i flaith \"księcia\", chociaż ponieważ nazwy utworzone z \"flaith\" są prawie wyłącznie kobiece, zazwyczaj jest interpretowane jako oznacza \"księżniczka\".</p>", "Ophélia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ofelia</b>.</p><b>Ofelia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>ophelos</i> oznaczającego „pomoc”. Pierwszy raz użył go <a href=\"https://pl.wikipedia.org/wiki/Jacopo_Sannazaro\" target=\"_blank\" rel=\"noopener noreferrer\">Jacopo Sannazaro</a> w wierszu <i>Arcadia</i>, a spopularyzował <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">William Szekspir</a> w dramacie <a href=\"https://pl.wikipedia.org/wiki/Hamlet\" target=\"_blank\" rel=\"noopener noreferrer\">Hamlet</a>. Jako <i>Ophelia</i> zdobyło pewną popularność w kulturze brytyjskiej.", "Olha-Ivanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olha</b>.</p><p>Olha to ukraińskie imię żeńskie związane z Olgą. Volha to białoruski wariant.</p>", "Olha-Kateryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olha</b>.</p><p>Olha to ukraińskie imię żeńskie związane z Olgą. Volha to białoruski wariant.</p>", "Olha-Yana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olha</b>.</p><p>Olha to ukraińskie imię żeńskie związane z Olgą. Volha to białoruski wariant.</p>", "Olena-Evelina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olena</b>.</p><b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Olivia Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olivia</b>.</p><p>Olivia Theresa Longott (ur. Olivia Theresa Longot; 15 lutego 1981, Brooklyn, Nowy Jork, USA) - amerykańska piosenkarka.</p>", "Oxána": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oksana</b>.</p><b>Ksenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „gościnna” (Ξενία, dosł. „życzliwa dla obcych”), popularne zwłaszcza w krajach prawosławnych: rosyjskie <b>Ксения</b> (<i><b>Ksienija</b></i>), <b>Аксиния</b> (<i><b>Aksinija</b></i>), ukraińskie <b>Ксенія</b> (<i><b>Ksenija</b></i>), <b>Ксеня</b> (<i><b>Ksenia</b></i>) oraz pochodne <b>Оксана</b> (<i><b>Oksana</b></i>), białoruskie <b>Ксенія</b> (<i><b>Ksenìâ</b></i>), czeskie <b>Xenie</b>, słowackie <b>Xeni</b>.", "Oktaviani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oktavian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oktawian</b>.</p><b>Oktawian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> oznaczające \"członek rzymskiego rodu <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Oktawiusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawiuszów</a>\" (ród <i>Octavia</i>). W Polsce imię to pojawiło się dopiero w XIX w..", "Oli̇vi̇a": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Oliwia</b>.</p><b>Oliwia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, etymologicznie powiązane z pospolitym wyrazem <i>oliva</i>, „drzewo oliwne, owoc oliwki, oliwka”. Znane było w starożytności. Istnieją dwie patronki tego imienia w <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościele katolickim</a>, jednak właściwe brzmienie ich imienia nie jest pewne – w przypadku jednego z nich Oliwia występuje przemiennie z <b>Oliwą</b>, w innym – z <b>Libią</b> (<a href=\"https://pl.wikipedia.org/wiki/Liba_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Libą</a>) na skutek późnołacińskiej wymowy <i>Olibia</i>. Niektóre źródła wskazują, że jest to imię pochodzenia literackiego, wymyślone przez <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Szekspira</a> na potrzeby komedii <a href=\"https://pl.wikipedia.org/wiki/Wiecz%C3%B3r_Trzech_Kr%C3%B3li\" target=\"_blank\" rel=\"noopener noreferrer\"><i>Wieczór Trzech Króli, lub co chcecie</i></a>.", "Olafa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Olaf</b>.</p><b>Olaf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Pierwotna forma brzmiała Aslaf. Wywodzi się od słów <i>As</i> (bóg – zobacz <a href=\"https://pl.wikipedia.org/wiki/Azowie\" target=\"_blank\" rel=\"noopener noreferrer\">Asowie</a>) i <i>laf</i> (słowo, które przeszło w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> <i>love</i>), czyli „umiłowany przez bogów”. Inna wersja etymologii głosi, że imię ma znaczenie „syn starego człowieka”.", "Oana-Mădălina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oana</b>.</p><p>Ioana lub Oana to żeńskie imię pochodzenia rumuńskiego. Jest on równoważny z angielską nazwą Joan, a męska wersja John, wszystkie pochodzące od hebrajskiej nazwy Yohanan.</p>", "Otilija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Otilia</b>.</p><p>Otilia to kobiece imię. Znanymi osobami z tej nazwy są: Otilia Bădescu (ur. 1970), rumuńska tenisistka tabeli Otilia Brumă (ur. 1992), rumuński piosenkarz-powieściciel Otilia Cazimir (1894-1967), rumuńskiego poety Otilia Larrañaga, meksykańska tancerka i aktorka Otilia Lux, gwatemalska liderka społeczna Otilia Pasarica (ur. 1968), rumuńczyk w siatkówce Otilia Ruicu-Eșanu (ur. 1978), rumuinską atletkę biegów i terenu</p>", "Oksana-Diana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oksana</b>.</p><b>Ksenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „gościnna” (Ξενία, dosł. „życzliwa dla obcych”), popularne zwłaszcza w krajach prawosławnych: rosyjskie <b>Ксения</b> (<i><b>Ksienija</b></i>), <b>Аксиния</b> (<i><b>Aksinija</b></i>), ukraińskie <b>Ксенія</b> (<i><b>Ksenija</b></i>), <b>Ксеня</b> (<i><b>Ksenia</b></i>) oraz pochodne <b>Оксана</b> (<i><b>Oksana</b></i>), białoruskie <b>Ксенія</b> (<i><b>Ksenìâ</b></i>), czeskie <b>Xenie</b>, słowackie <b>Xeni</b>.", "Oko": "<b>Oko</b> – <a href=\"https://pl.wikipedia.org/wiki/Receptor\" target=\"_blank\" rel=\"noopener noreferrer\">receptorowy</a> <a href=\"https://pl.wikipedia.org/wiki/Narz%C4%85dy_zmys%C5%82%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">narząd zmysłu</a> <a href=\"https://pl.wikipedia.org/wiki/Wzrok\" target=\"_blank\" rel=\"noopener noreferrer\">wzroku</a>. Najprostsze oko ma tylko zdolność wykrywania pewnego zakresu <a href=\"https://pl.wikipedia.org/wiki/Promieniowanie_elektromagnetyczne\" target=\"_blank\" rel=\"noopener noreferrer\">promieniowania elektromagnetycznego</a>; bardziej skomplikowane jest w stanie dostarczyć informacji o kierunku padania <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awiat%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">światła</a>, jego intensywności oraz kształtach obiektów.", "Olha-Anhelina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olha</b>.</p><p>Olha to ukraińskie imię żeńskie związane z Olgą. Volha to białoruski wariant.</p>", "Oana-Alina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Oana</b>.</p><p>Ioana lub Oana to żeńskie imię pochodzenia rumuńskiego. Jest on równoważny z angielską nazwą Joan, a męska wersja John, wszystkie pochodzące od hebrajskiej nazwy Yohanan.</p>", "Orelia": "<p>Orelia (or its variants Orelious, Ornellas, Orellana, Orellia, Ortelius lub Orelias) to imiona żeńskie występujące głównie w Europie, krajach śródziemnomorskimi i Ameryce Południowej. Pochodzące z łacińskiej Aurelius rodziny oznacza \"złote\".</p>", "Oihane": "<p>Oihane to kobiece baskie imię. Znani ludzie z nazwiskiem to: Oihane Hernández (ur. 2000), Hiszpański piłkarz Oihane Otaegi (ur. 1977), Hiszpan kręgowy Oihane Valdezate (ur. 2000, Hiszpańska piłkarza</p>", "Olha-Olena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olha</b>.</p><p>Olha to ukraińskie imię żeńskie związane z Olgą. Volha to białoruski wariant.</p>", "Olena-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Olena</b>.</p><b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272."};
